from typing import List

class Solution:
    def getTopThree(self, teamNum: int, matches: List[List[str]]) -> List[str]:
        # 1. 检查 teamNum 合法性
        if teamNum < 3 or teamNum > 15:
            return []

        # 2. 收集所有队伍并去重，数量必须等于 teamNum
        teams_set = set()
        for m in matches:
            teams_set.add(m[0])
            teams_set.add(m[3])
        teams = list(teams_set)
        if len(teams) != teamNum:
            return []

        # 3. 初始化统计数据
        points = {t: 0 for t in teams}
        goals_for = {t: 0 for t in teams}
        goals_against = {t: 0 for t in teams}
        played = set()  # 记录已比赛的对阵

        for m in matches:
            a, ga, gb, b = m[0], int(m[1]), int(m[2]), m[3]
            # 记录已比赛的对阵（排序后存入集合避免重复）
            played.add(tuple(sorted([a, b])))

            # 累加进球与失球
            goals_for[a] += ga
            goals_against[a] += gb
            goals_for[b] += gb
            goals_against[b] += ga

            # 计分规则：胜 3 分，平 1 分，负 0 分
            if ga > gb:
                points[a] += 3
            elif ga < gb:
                points[b] += 3
            else:
                points[a] += 1
                points[b] += 1

        # 4. 检查比赛场次是否超限
        max_matches = teamNum * (teamNum - 1) // 2
        if len(matches) > max_matches:
            return []

        # 5. 检查每对队伍是否都有比赛记录
        n = len(teams)
        for i in range(n):
            for j in range(i + 1, n):
                if tuple(sorted([teams[i], teams[j]])) not in played:
                    return []  # 有队伍对之间缺少比赛

        # 6. 检查是否存在积分和净胜球完全相同的队伍
        for i in range(n):
            for j in range(i + 1, n):
                gd_i = goals_for[teams[i]] - goals_against[teams[i]]
                gd_j = goals_for[teams[j]] - goals_against[teams[j]]
                if points[teams[i]] == points[teams[j]] and gd_i == gd_j:
                    return []  # 并列且不可区分

        # 7. 排序：积分降序 → 净胜球降序，取前 3 名
        teams.sort(key=lambda t: (-points[t], -(goals_for[t] - goals_against[t])))
        return teams[:3]
```

```java
import java.util.*;

class Solution {
    public List<String> getTopThree(int teamNum, List<List<String>> matches) {
        // 1. 检查 teamNum 合法性
        if (teamNum < 3 || teamNum > 15) {
            return new ArrayList<>();
        }

        // 2. 收集所有队伍并去重
        Set<String> teamSet = new HashSet<>();
        for (List<String> m : matches) {
            teamSet.add(m.get(0));
            teamSet.add(m.get(3));
        }
        List<String> teams = new ArrayList<>(teamSet);
        if (teams.size() != teamNum) {
            return new ArrayList<>();
        }

        // 3. 初始化统计数据
        Map<String, Integer> points = new HashMap<>();
        Map<String, Integer> goalsFor = new HashMap<>();
        Map<String, Integer> goalsAgainst = new HashMap<>();
        for (String t : teams) {
            points.put(t, 0);
            goalsFor.put(t, 0);
            goalsAgainst.put(t, 0);
        }
        Set<String> played = new HashSet<>();

        for (List<String> m : matches) {
            String a = m.get(0), b = m.get(3);
            int ga = Integer.parseInt(m.get(1));
            int gb = Integer.parseInt(m.get(2));

            // 记录已比赛的对阵
            String key = a.compareTo(b) < 0 ? a + "|" + b : b + "|" + a;
            played.add(key);

            // 累加进球与失球
            goalsFor.put(a, goalsFor.get(a) + ga);
            goalsAgainst.put(a, goalsAgainst.get(a) + gb);
            goalsFor.put(b, goalsFor.get(b) + gb);
            goalsAgainst.put(b, goalsAgainst.get(b) + ga);

            // 计分规则
            if (ga > gb) {
                points.put(a, points.get(a) + 3);
            } else if (ga < gb) {
                points.put(b, points.get(b) + 3);
            } else {
                points.put(a, points.get(a) + 1);
                points.put(b, points.get(b) + 1);
            }
        }

        // 4. 检查比赛场次
        int maxMatches = teamNum * (teamNum - 1) / 2;
        if (matches.size() > maxMatches) {
            return new ArrayList<>();
        }

        // 5. 检查每对队伍是否都有比赛
        int n = teams.size();
        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                String key = teams.get(i).compareTo(teams.get(j)) < 0
                    ? teams.get(i) + "|" + teams.get(j)
                    : teams.get(j) + "|" + teams.get(i);
                if (!played.contains(key)) {
                    return new ArrayList<>();
                }
            }
        }

        // 6. 检查积分和净胜球并列
        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                int gdI = goalsFor.get(teams.get(i)) - goalsAgainst.get(teams.get(i));
                int gdJ = goalsFor.get(teams.get(j)) - goalsAgainst.get(teams.get(j));
                if (points.get(teams.get(i)).equals(points.get(teams.get(j))) && gdI == gdJ) {
                    return new ArrayList<>();
                }
            }
        }

        // 7. 排序取前三
        teams.sort((a, b) -> {
            int cmp = points.get(b).compareTo(points.get(a));
            if (cmp != 0) return cmp;
            int gdA = goalsFor.get(a) - goalsAgainst.get(a);
            int gdB = goalsFor.get(b) - goalsAgainst.get(b);
            return Integer.compare(gdB, gdA);
        });

        return new ArrayList<>(teams.subList(0, Math.min(3, teams.size())));
    }
}
