from typing import List

class Solution:
    def splitSQLToFiles(self, splitLine: int, sqlText: List[str]) -> int:
        # 1. 合法性校验
        if splitLine < 1 or splitLine > 10000:
            return 0
        n = len(sqlText)
        if n == 0:
            return 0

        # 2. 解析每行的事务标签，建 tag → {行号} 映射
        tag_to_rows = {}
        for idx, row in enumerate(sqlText):
            statements = row.split(';')
            # 去掉末尾空串（行以 ; 结尾时产生）
            while statements and statements[-1] == '':
                statements.pop()
            for stmt in statements:
                stmt = stmt.strip()
                if not stmt:
                    continue
                # 提取 [Tn] 标签
                if stmt.startswith('['):
                    end = stmt.find(']')
                    if end != -1:
                        tag = stmt[1:end]
                        if tag.startswith('T'):
                            tag_to_rows.setdefault(tag, set()).add(idx)

        # 3. 并查集：按事务标签合并行号
        parent = list(range(n))

        def find(x):
            while parent[x] != x:
                parent[x] = parent[parent[x]]
                x = parent[x]
            return x

        def union(x, y):
            px, py = find(x), find(y)
            if px != py:
                parent[px] = py

        for rows in tag_to_rows.values():
            rows_list = list(rows)
            for i in range(1, len(rows_list)):
                union(rows_list[0], rows_list[i])

        # 4. 按连通分量分组 → (首次出现行号, 行数)
        groups = {}
        for i in range(n):
            root = find(i)
            groups.setdefault(root, set()).add(i)

        group_list = []
        for root, rows in groups.items():
            group_list.append((min(rows), len(rows)))
        group_list.sort()  # 按首次出现行号排序

        # 5. 贪心分配文件
        files = 0
        cur_size = 0
        for _, gsize in group_list:
            if cur_size == 0 or cur_size + gsize > splitLine:
                files += 1                           # 新建文件（即使超限也独占）
                cur_size = gsize
            else:
                cur_size += gsize                    # 放入当前文件

        return files
