```c
#include <string.h>
#include <stdlib.h>

int splitSQLToFiles(int splitLine, char** sqlText, int sqlTextSize) {
    // 1. 合法性校验
    if (splitLine < 1 || splitLine > 10000) return 0;
    int n = sqlTextSize;
    if (n == 0) return 0;

    // 2. 解析标签
    // 用邻接表记录每个标签涉及的行（最多 1000 标签 × 若干行）
    int** tagRows = (int**)calloc(1001, sizeof(int*));
    int* tagSizes = (int*)calloc(1001, sizeof(int));
    int* tagCaps = (int*)calloc(1001, sizeof(int));

    for (int idx = 0; idx < n; idx++) {
        const char* row = sqlText[idx];
        int rowLen = (int)strlen(row);
        int pos = 0;
        while (pos < rowLen) {
            // 找 ; 分隔
            int semi = pos;
            while (semi < rowLen && row[semi] != ';') semi++;
            int stmtLen = semi - pos;

            if (stmtLen > 0) {
                const char* stmt = row + pos;
                // 跳过前导空格
                while (stmtLen > 0 && stmt[0] == ' ') { stmt++; stmtLen--; }
                // 检查 [T
                if (stmtLen > 2 && stmt[0] == '[' && stmt[1] == 'T') {
                    int br = 2;
                    while (br < stmtLen && stmt[br] != ']') br++;
                    if (br < stmtLen) {
                        // 提取标签号
                        int tagNum = 0;
                        for (int k = 2; k < br; k++) {
                            if (stmt[k] >= '0' && stmt[k] <= '9')
                                tagNum = tagNum * 10 + (stmt[k] - '0');
                        }
                        if (tagNum >= 1 && tagNum <= 1000) {
                            // 加入 tagRows[tagNum]
                            if (tagSizes[tagNum] >= tagCaps[tagNum]) {
                                tagCaps[tagNum] = tagCaps[tagNum] == 0 ? 4 : tagCaps[tagNum] * 2;
                                tagRows[tagNum] = (int*)realloc(tagRows[tagNum],
                                    tagCaps[tagNum] * sizeof(int));
                            }
                            // 去重：只加首次出现的行
                            int dup = 0;
                            for (int k = 0; k < tagSizes[tagNum]; k++) {
                                if (tagRows[tagNum][k] == idx) { dup = 1; break; }
                            }
                            if (!dup)
                                tagRows[tagNum][tagSizes[tagNum]++] = idx;
                        }
                    }
                }
            }

            pos = semi + 1;
            if (semi == rowLen) break;
        }
    }

    // 3. 并查集
    int* parent = (int*)malloc(n * sizeof(int));
    for (int i = 0; i < n; i++) parent[i] = i;

    // find 内联
    for (int t = 1; t <= 1000; t++) {
        if (tagSizes[t] <= 1) continue;
        int first = tagRows[t][0];
        // 压缩 first
        int fRoot = first;
        while (parent[fRoot] != fRoot) fRoot = parent[fRoot];
        for (int k = 1; k < tagSizes[t]; k++) {
            int x = tagRows[t][k];
            int xRoot = x;
            while (parent[xRoot] != xRoot) xRoot = parent[xRoot];
            if (xRoot != fRoot) parent[xRoot] = fRoot;
        }
    }
    // 路径压缩
    for (int i = 0; i < n; i++) {
        int r = i;
        while (parent[r] != r) r = parent[r];
        parent[i] = r;
    }

    // 4. 分组
    int* groupMin = (int*)malloc(n * sizeof(int));
    int* groupCnt = (int*)calloc(n, sizeof(int));
    for (int i = 0; i < n; i++) {
        int r = parent[i];
        if (groupCnt[r] == 0)
            groupMin[r] = i;
        else if (i < groupMin[r])
            groupMin[r] = i;
        groupCnt[r]++;
    }

    // 收集非空组并冒泡排序
    int* order = (int*)malloc(n * sizeof(int));
    int orderSize = 0;
    for (int i = 0; i < n; i++) {
        if (groupCnt[i] > 0)
            order[orderSize++] = i;
    }
    for (int i = 0; i < orderSize; i++) {
        for (int j = i + 1; j < orderSize; j++) {
            if (groupMin[order[i]] > groupMin[order[j]]) {
                int tmp = order[i];
                order[i] = order[j];
                order[j] = tmp;
            }
        }
    }

    // 5. 贪心分配
    int files = 0, curSize = 0;
    for (int i = 0; i < orderSize; i++) {
        int gsize = groupCnt[order[i]];
        if (curSize == 0 || curSize + gsize > splitLine) {
            files++;              // 新建文件（即使超限也独占）
            curSize = gsize;
        } else {
            curSize += gsize;     // 放入当前文件
        }
    }

    // 清理
    for (int t = 1; t <= 1000; t++) free(tagRows[t]);
    free(tagRows); free(tagSizes); free(tagCaps);
    free(parent); free(groupMin); free(groupCnt); free(order);

    return files;
}
