class Solution {
    public int minJumps(String treeLevelOrder, String frm, String to) {
        // 1. 拆分
        String[] nodes = treeLevelOrder.split(",");
        for (int i = 0; i < nodes.length; i++)
            nodes[i] = nodes[i].trim();

        // 2. 定位
        int posFrm = -1, posTo = -1;
        for (int i = 0; i < nodes.length; i++) {
            if (nodes[i].equals(frm)) posFrm = i;
            if (nodes[i].equals(to)) posTo = i;
        }
        if (posFrm == -1 || posTo == -1) return -1;

        // 3. 深度
        int d1 = depth(posFrm), d2 = depth(posTo);
        int origD1 = d1, origD2 = d2;

        // 4. 同一深度
        while (d1 > d2) { posFrm = (posFrm - 1) / 2; d1--; }
        while (d2 > d1) { posTo = (posTo - 1) / 2; d2--; }

        // 5. LCA
        while (posFrm != posTo) {
            posFrm = (posFrm - 1) / 2;
            posTo = (posTo - 1) / 2;
        }

        return origD1 + origD2 - 2 * depth(posFrm);
    }

    private int depth(int pos) {
        int d = 0;
        while (pos > 0) { pos = (pos - 1) / 2; d++; }
        return d;
    }
}
