#include <stdlib.h>

// 升序排序比较函数
static int cmp(const void* a, const void* b) {
    int x = *(int*)a, y = *(int*)b;
    if (x < y) return -1;
    if (x > y) return 1;
    return 0;
}

int** threeSumWithParity(int* nums, int numsSize, int target, int* returnSize, int** returnColumnSizes) {
    // 排序，便于双指针和去重
    qsort(nums, numsSize, sizeof(int), cmp);

    int cap = 4096;
    int** ans = (int**)malloc(cap * sizeof(int*));
    *returnColumnSizes = (int*)malloc(cap * sizeof(int));
    int cnt = 0;

    for (int i = 0; i < numsSize - 2; i++) {
        // 跳过重复的第一个元素
        if (i > 0 && nums[i] == nums[i - 1]) continue;
        int j = i + 1, k = numsSize - 1;
        while (j < k) {
            long long s = (long long)nums[i] + nums[j] + nums[k];
            if (s == target) {
                // 统计奇数个数
                int odd = (nums[i] & 1) + (nums[j] & 1) + (nums[k] & 1);
                if (odd >= 2) {
                    if (cnt >= cap) {
                        cap *= 2;
                        ans = (int**)realloc(ans, cap * sizeof(int*));
                        *returnColumnSizes = (int*)realloc(*returnColumnSizes, cap * sizeof(int));
                    }
                    ans[cnt] = (int*)malloc(3 * sizeof(int));
                    ans[cnt][0] = nums[i];
                    ans[cnt][1] = nums[j];
                    ans[cnt][2] = nums[k];
                    (*returnColumnSizes)[cnt] = 3;
                    cnt++;
                }
                // 跳过重复的 j 和 k
                while (j < k && nums[j] == nums[j + 1]) j++;
                while (j < k && nums[k] == nums[k - 1]) k--;
                j++;
                k--;
            } else if (s < target) {
                j++;
            } else {
                k--;
            }
        }
    }

    *returnSize = cnt;
    return ans;
}
