static int split(char* s, char delim, char** parts, int maxParts) {
    int cnt = 0;
    char* start = s;
    for (int i = 0; ; i++) {
        if (s[i] == delim || s[i] == '\0') {
            parts[cnt++] = start;
            if (cnt >= maxParts || s[i] == '\0') break;
            s[i] = '\0';
            start = s + i + 1;
        }
    }
    return cnt;
}

