using namespace std;

static string toLower(const string& s) {
  string t = s;
  for (char& c : t) c = static_cast<char>(tolower(static_cast<unsigned char>(c)));
  return t;
}

static bool isDelim(char c) {
  return isspace(static_cast<unsigned char>(c)) || c == ',' || c == '.' ||
         c == '!' || c == '?' || c == ';' || c == ':';
}

static vector<string> tokenize(const string& log) {
  vector<string> words;
  string cur;
  for (char c : log) {
    if (isDelim(c)) {
      if (!cur.empty()) {
        words.push_back(toLower(cur));
        cur.clear();
      }
    } else {
      cur += c;
    }
  }
  if (!cur.empty()) words.push_back(toLower(cur));
  return words;
}

class Solution {
 public:
  vector<int> analyzeLogKeywords(vector<string>& logs, vector<string>& keywords) {
    int m = static_cast<int>(keywords.size());
    vector<string> kws;
    for (auto& k : keywords) kws.push_back(toLower(k));

    vector<int> counts(m, 0);
    for (auto& log : logs) {
      auto words = tokenize(log);
      for (int ki = 0; ki < m; ki++) {
        for (auto& w : words) {
          if (w == kws[ki]) counts[ki]++;
        }
      }
    }

    vector<int> pairs;
    for (int i = 0; i < m; i++) {
      for (int j = i + 1; j < m; j++) {
        int co = 0;
        for (auto& log : logs) {
          auto words = tokenize(log);
          bool hasI = false, hasJ = false;
          for (auto& w : words) {
            if (w == kws[i]) hasI = true;
            if (w == kws[j]) hasJ = true;
          }
          if (hasI && hasJ) co++;
        }
        if (co >= 2) {
          pairs.push_back(i);
          pairs.push_back(j);
        }
      }
    }

    counts.insert(counts.end(), pairs.begin(), pairs.end());
    return counts;
  }
};
