```javascript
var processDataArray = function(data, operations) {
    // 32位popcount
    function popcount32(x) {
        var u = x >>> 0; // 转为无符号32位
        var cnt = 0;
        while (u) { cnt++; u &= u - 1; }
        return cnt;
    }

    // 按(popcount, 数值)升序排序
    function sortArr(arr) {
        arr.sort(function(u, v) {
            var cu = popcount32(u), cv = popcount32(v);
            if (cu !== cv) return cu - cv;
            return u - v;
        });
    }

    var arr = data.slice();
    sortArr(arr);

    for (var k = 0; k < operations.length; k++) {
        var i = operations[k][0], j = operations[k][1];
        var a = arr[i];
        var b = (i === j) ? a : arr[j];
        var merged = a | b;

        if (i === j) {
            arr.splice(i, 1);
        } else {
            var lo = Math.min(i, j), hi = Math.max(i, j);
            arr.splice(hi, 1);
            arr.splice(lo, 1);
        }
        arr.push(merged);
        sortArr(arr);
    }

    return arr;
};
