```c
#include <stdlib.h>

// 32位popcount：统计二进制中1的个数
static int popcount32(int x) {
    unsigned u = (unsigned)x;
    int cnt = 0;
    while (u) { cnt++; u &= u - 1; }
    return cnt;
}

// 比较函数：先按popcount升序，再按数值升序（用比较避免int减法溢出）
static int cmp(const void* a, const void* b) {
    int x = *(int*)a, y = *(int*)b;
    int cx = popcount32(x), cy = popcount32(y);
    if (cx != cy) return cx - cy;
    if (x < y) return -1;
    if (x > y) return 1;
    return 0;
}

// 从数组中删除指定下标
static void removeAt(int* arr, int* size, int idx) {
    for (int i = idx; i < *size - 1; i++) arr[i] = arr[i + 1];
    (*size)--;
}

int* processDataArray(int* data, int dataSize, int** operations, int operationsSize, int* operationsColSize, int* returnSize) {
    int cap = dataSize + operationsSize + 1;
    int* arr = (int*)malloc(cap * sizeof(int));
    int size = dataSize;
    for (int i = 0; i < size; i++) arr[i] = data[i];

    // 初始排序
    qsort(arr, size, sizeof(int), cmp);

    for (int op = 0; op < operationsSize; op++) {
        int i = operations[op][0];
        int j = operations[op][1];
        int a = arr[i];
        int b = (i == j) ? a : arr[j];
        int merged = a | b;

        if (i == j) {
            removeAt(arr, &size, i);
        } else {
            int lo = i < j ? i : j;
            int hi = i > j ? i : j;
            removeAt(arr, &size, hi);
            removeAt(arr, &size, lo);
        }
        arr[size++] = merged;
        qsort(arr, size, sizeof(int), cmp);
    }

    *returnSize = size;
    int* result = (int*)malloc(size * sizeof(int));
    for (int i = 0; i < size; i++) result[i] = arr[i];
    free(arr);
    return result;
}
