```javascript
var processString = function(s) {
    // 分离数字和字母
    var digits = [];
    var letters = [];
    for (var i = 0; i < s.length; i++) {
        var c = s[i];
        if (c >= '0' && c <= '9') {
            digits.push(c);
        } else if (c >= 'A' && c <= 'Z') {
            letters.push(c);
        }
    }
    // 只含一类字符时直接返回原串
    if (digits.length === 0 || letters.length === 0) {
        return s;
    }
    var parts = [];
    var n = Math.min(digits.length, letters.length);
    // 交替输出
    for (var i = 0; i < n; i++) {
        parts.push(digits[i]); // 先输出数字
        var cnt = parseInt(digits[i]);
        // 数字为 0 时不输出对应字母
        if (cnt > 0) {
            for (var k = 0; k < cnt; k++) {
                parts.push(letters[i]);
            }
        }
    }
    // 拼接较长一侧的余量
    if (digits.length > n) {
        for (var i = n; i < digits.length; i++) {
            parts.push(digits[i]);
        }
    } else if (letters.length > n) {
        for (var i = n; i < letters.length; i++) {
            parts.push(letters[i]);
        }
    }
    return parts.join('');
};
