var sortConvertedNums = function(nums, base) {
    // 进制字符映射
    var digits = "0123456789abcdef";
    // 将数字转换为 base 进制字符串
    function toBase(n) {
        if (n === 0) return "0";
        var parts = [];
        while (n > 0) {
            parts.push(digits[n % base]);
            n = Math.floor(n / base);
        }
        return parts.reverse().join('');
    }
    // 转换每个数字
    var converted = nums.map(function(x) { return toBase(x); });
    // 按原整数降序排列下标
    var order = [];
    for (var i = 0; i < nums.length; i++) order.push(i);
    order.sort(function(a, b) { return nums[b] - nums[a]; });
    // 按排序后的下标收集结果
    var result = [];
    for (var i = 0; i < order.length; i++) {
        result.push(converted[order[i]]);
    }
    return result;
};
