char** sortConvertedNums(int* nums, int numsSize, int base, int* returnSize) {
    *returnSize = numsSize;
    // 字符映射表
    const char* digits = "0123456789abcdef";

    // 转换为 base 进制字符串
    char** converted = (char**)malloc(numsSize * sizeof(char*));
    for (int i = 0; i < numsSize; i++) {
        int n = nums[i];
        if (n == 0) {
            converted[i] = (char*)malloc(2);
            converted[i][0] = '0';
            converted[i][1] = '\0';
            continue;
        }
        char buf[32];
        int pos = 0;
        while (n > 0) {
            buf[pos++] = digits[n % base];
            n /= base;
        }
        // 逆序拼回
        converted[i] = (char*)malloc(pos + 1);
        for (int j = 0; j < pos; j++) {
            converted[i][j] = buf[pos - 1 - j];
        }
        converted[i][pos] = '\0';
    }

    // 按原整数降序排列下标
    int* order = (int*)malloc(numsSize * sizeof(int));
    for (int i = 0; i < numsSize; i++) order[i] = i;
    // 选择排序
    for (int i = 0; i < numsSize; i++) {
        int best = i;
        for (int j = i + 1; j < numsSize; j++) {
            if (nums[order[j]] > nums[order[best]]) best = j;
        }
        int tmp = order[i];
        order[i] = order[best];
        order[best] = tmp;
    }

    // 按排序后的下标收集结果
    char** result = (char**)malloc(numsSize * sizeof(char*));
    for (int i = 0; i < numsSize; i++) {
        result[i] = converted[order[i]];
    }
    free(converted);
    free(order);
    return result;
}
