#include <stdlib.h>

// 并查集 find：路径压缩
static int find(int* parent, int x) {
    while (parent[x] != x) {
        parent[x] = parent[parent[x]];
        x = parent[x];
    }
    return x;
}

int maxZoneImbalance(int* loads, int loadsSize, int** edges, int edgesSize, int* edgesColSize) {
    // 无边则无有效供电区
    if (edgesSize == 0) return -1;

    // 并查集初始化
    int* parent = (int*)malloc(loadsSize * sizeof(int));
    for (int i = 0; i < loadsSize; i++) parent[i] = i;

    // 按边合并同一供电区
    for (int i = 0; i < edgesSize; i++) {
        int a = find(parent, edges[i][0]);
        int b = find(parent, edges[i][1]);
        if (a != b) parent[b] = a;
    }

    // 获取每个节点的根
    int* root = (int*)malloc(loadsSize * sizeof(int));
    for (int i = 0; i < loadsSize; i++) root[i] = find(parent, i);

    int ans = -1;
    int* visited = (int*)calloc(loadsSize, sizeof(int));
    for (int i = 0; i < loadsSize; i++) {
        if (visited[i]) continue;
        int r = root[i];
        int cnt = 0, mn = 0x7fffffff, mx = -1;
        for (int j = 0; j < loadsSize; j++) {
            if (root[j] == r) {
                visited[j] = 1;
                cnt++;
                if (loads[j] < mn) mn = loads[j];
                if (loads[j] > mx) mx = loads[j];
            }
        }
        // 节点数 >= 2 才算有效供电区
        if (cnt >= 2) {
            int imbalance = (mx - mn) * cnt;
            if (imbalance > ans) ans = imbalance;
        }
    }

    free(parent);
    free(root);
    free(visited);
    return ans;
}
