2026年新系统题库（含题目详解）.solution:
## 解题思路

本题是**字符串解析 + 模拟分组**，可按以下步骤处理：

1. **合法性检查**：遍历 $SN$，若出现非字母、非数字且非 `-` 的字符，直接返回 `""`。
2. **提取有效字符**：按从左到右顺序收集所有字母与数字，忽略 `-`；若收集结果为空（如全为破折号），返回 `""`。
3. **统一大小写**：将小写字母转为大写。
4. **按 $m$ 分组**：
   - 设有效字符总数为 $n$，余数 $r = n \bmod m$；
   - 若 $r \neq 0$，第一段长度为 $r$，其余每段长度为 $m$；
   - 若 $r = 0$，每段长度均为 $m$。
5. 用 `-` 连接各段输出。

**常见假解**：

- 保留原破折号位置再插入新破折号 → 应先去掉所有 `-$ 再重排；
- 忘记转大写 → `2n` 应输出 `2N`；
- $n \bmod m \neq 0$ 时仍从第一段取 $m$ 个字符 → 首段长度应为余数 $r$；
- $n \bmod m = 0$ 时错误地让首段更短 → 此时应全部均分，无特例首段；
- 把 `-` 当成有效字符计入分组 → 只统计字母数字；
- 遇到 `@`、空格等仍继续处理 → 异常场景应直接返回 `""`。

## 复杂度分析

设 $n$ 为 $SN$ 长度，$|sn| < 10000$，$m \le 10$。

- 时间：$O(n)$，单次遍历提取与分组；
- 空间：$O(n)$ 存储提取后的字符序列。

## 代码实现

#code-switcher
```python
class Solution:
    def rearrangeSN(self, sn: str, m: int) -> str:
        # 仅允许字母、数字与破折号；其它字符视为异常
        for c in sn:
            if not (c.isalnum() or c == "-"):
                return ""

        chars = []
        # 按原顺序提取字母数字并转大写
        for c in sn:
            if c.isalnum():
                chars.append(c.upper())

        if not chars:
            return ""

        n = len(chars)
        rem = n % m
        groups = []
        idx = 0
        # 有余数时首段长度不足 m
        if rem != 0:
            groups.append("".join(chars[idx : idx + rem]))
            idx += rem
        while idx < n:
            groups.append("".join(chars[idx : idx + m]))
            idx += m
        return "-".join(groups)
```

```java
public class Solution {
    public String rearrangeSN(String sn, int m) {
        // 异常字符：非字母数字且非破折号
        for (int i = 0; i < sn.length(); i++) {
            char c = sn.charAt(i);
            if (!Character.isLetterOrDigit(c) && c != '-') return "";
        }

        StringBuilder chars = new StringBuilder();
        for (int i = 0; i < sn.length(); i++) {
            char c = sn.charAt(i);
            if (Character.isLetterOrDigit(c)) {
                chars.append(Character.toUpperCase(c));
            }
        }
        if (chars.length() == 0) return "";

        int n = chars.length();
        int rem = n % m;
        StringBuilder ans = new StringBuilder();
        int idx = 0;
        // 首段承接余数长度
        if (rem != 0) {
            if (ans.length() > 0) ans.append('-');
            ans.append(chars, idx, idx + rem);
            idx += rem;
        }
        while (idx < n) {
            if (ans.length() > 0) ans.append('-');
            ans.append(chars, idx, idx + m);
            idx += m;
        }
        return ans.toString();
    }
}
```

```cpp
#include <cctype>
#include <string>
#include <vector>

using namespace std;

class Solution {
 public:
  string rearrangeSN(string sn, int m) {
    // 校验字符集：仅字母、数字、破折号合法
    for (char c : sn) {
      if (!isalnum((unsigned char)c) && c != '-') return "";
    }

    vector<char> chars;
    for (char c : sn) {
      if (isalnum((unsigned char)c)) {
        chars.push_back((char)toupper((unsigned char)c));
      }
    }
    if (chars.empty()) return "";

    int n = (int)chars.size();
    int rem = n % m;
    vector<string> groups;
    int idx = 0;
    // 不能整除 m 时，余数段放在第一段
    if (rem != 0) {
      groups.emplace_back(chars.begin(), chars.begin() + rem);
      idx += rem;
    }
    while (idx < n) {
      groups.emplace_back(chars.begin() + idx, chars.begin() + idx + m);
      idx += m;
    }

    string ans;
    for (size_t i = 0; i < groups.size(); i++) {
      if (i) ans.push_back('-');
      ans += groups[i];
    }
    return ans;
  }
};
