```javascript
/**
 * @param {string} sn - 一个有效的 SN 地址字符串
 * @param {number} m - 每个分组恰好包含的字符数
 * @return {string} - 重新排列后的 SN 地址字符串（含外层双引号）
 */
var rearrangeSN = function(sn, m) {
    // 合法性检查：仅允许字母、数字、破折号
    for (var k = 0; k < sn.length; k++) {
        var ch = sn[k];
        if (!((ch >= '0' && ch <= '9') ||
              (ch >= 'A' && ch <= 'Z') ||
              (ch >= 'a' && ch <= 'z') ||
               ch === '-')) {
            return '""';
        }
    }

    // 提取字母数字并转大写
    var chars = [];
    for (var k = 0; k < sn.length; k++) {
        var ch = sn[k];
        if ((ch >= '0' && ch <= '9') ||
            (ch >= 'A' && ch <= 'Z') ||
            (ch >= 'a' && ch <= 'z')) {
            chars.push(ch.toUpperCase());
        }
    }

    var n = chars.length;
    // 无有效字符
    if (n === 0) return '""';

    var r = n % m;
    var groups = [];
    var idx = 0;
    // 首段（若有余数）
    if (r !== 0) {
        groups.push(chars.slice(idx, idx + r).join(''));
        idx += r;
    }
    // 其后每段长 m
    while (idx < n) {
        groups.push(chars.slice(idx, idx + m).join(''));
        idx += m;
    }
    return '"' + groups.join('-') + '"';
};
