#include <stdlib.h>
#include <string.h>
#include <ctype.h>

char* rearrangeSN(char* sn, int m) {
    // 合法性检查：只允许字母、数字、破折号
    int len = (int)strlen(sn);

    for (int i = 0; i < len; i++) {
        char c = sn[i];
        if (!isalnum((unsigned char)c) && c != '-') {
            // 异常场景，返回空字符串
            char* result = (char*)malloc(3);
            result[0] = '"';
            result[1] = '"';
            result[2] = '\0';
            return result;
        }
    }

    // 提取字母数字并转大写
    char* chars = (char*)malloc(len + 1);
    int cnt = 0;
    for (int i = 0; i < len; i++) {
        char c = sn[i];
        if (isalnum((unsigned char)c)) {
            chars[cnt++] = (char)toupper((unsigned char)c);
        }
    }
    chars[cnt] = '\0';

    // 无有效字符
    if (cnt == 0) {
        free(chars);
        char* result = (char*)malloc(3);
        result[0] = '"';
        result[1] = '"';
        result[2] = '\0';
        return result;
    }

    // 分组：余数 r，首段长 r（若 r>0），其余每段长 m
    int n = cnt;
    int r = n % m;
    int groups = (n + m - 1) / m;
    int resultLen = 2 + n + (groups - 1) + 1;
    char* result = (char*)malloc(resultLen);

    int pos = 0;
    result[pos++] = '"';
    int idx = 0;
    // 首段（若有余数）
    if (r != 0) {
        for (int j = 0; j < r; j++) result[pos++] = chars[idx++];
        if (idx < n) result[pos++] = '-';
    }
    // 其后每段长 m
    while (idx < n) {
        for (int j = 0; j < m; j++) result[pos++] = chars[idx++];
        if (idx < n) result[pos++] = '-';
    }
    result[pos++] = '"';
    result[pos] = '\0';

    free(chars);
    return result;
}
