 * @param {string} resA - 字符串A，只包含小写字母
 * @param {string} resB - 字符串B，只包含小写字母
 * @return {number} - 最小相等不同字符数，无解返回 -1
 */
var minDistinctAfterSwap = function(resA, resB) {
    var countA = new Array(26).fill(0);
    var countB = new Array(26).fill(0);

    // 统计频次
    for (var i = 0; i < resA.length; i++) {
        countA[resA.charCodeAt(i) - 97]++;
    }
    for (var i = 0; i < resB.length; i++) {
        countB[resB.charCodeAt(i) - 97]++;
    }

    // 当前不同字符个数
    var dA = 0, dB = 0;
    for (var i = 0; i < 26; i++) {
        if (countA[i] > 0) dA++;
        if (countB[i] > 0) dB++;
    }

    var ans = -1;
    for (var a = 0; a < 26; a++) {
        if (countA[a] === 0) continue;
        for (var b = 0; b < 26; b++) {
            if (countB[b] === 0) continue;
            var cand;
            if (a === b) {
                // 交换相同字符，字符串不变
                if (dA !== dB) continue;
                cand = dA;
            } else {
                // 交换后不同字符数增量公式
                var da = dA - (countA[a] === 1 ? 1 : 0) + (countA[b] === 0 ? 1 : 0);
                var db = dB - (countB[b] === 1 ? 1 : 0) + (countB[a] === 0 ? 1 : 0);
                if (da !== db) continue;
                cand = da;
            }
            if (ans === -1 || cand < ans) ans = cand;
        }
    }
    return ans;
};
