typedef struct {
    int parts[3];   // 第二、三、四段数值
    char* ip;       // 原 IP 字符串
} ValidIP;

// 校验 IP 合法性，合法时填充后三段数值
static bool parseValid(const char* ip, int* out) {
    int nums[4];
    const char* p = ip;
    for (int s = 0; s < 4; s++) {
        if (*p == '\0' || *p == '.') return false;  // 空段
        const char* start = p;
        while (*p && *p != '.') p++;
        int len = (int)(p - start);
        // 前导零规则：仅 "0" 合法
        if (len > 1 && start[0] == '0') return false;
        int v = 0;
        for (int i = 0; i < len; i++) {
            if (start[i] < '0' || start[i] > '9') return false;
            v = v * 10 + (start[i] - '0');
        }
        if (v < 0 || v > 255) return false;
        nums[s] = v;
        if (s < 3 && *p == '.') p++;
    }
    if (*p != '\0') return false;  // 多于四段
    if (nums[0] != 10) return false;
    out[0] = nums[1]; out[1] = nums[2]; out[2] = nums[3];
    return true;
}

static int cmpValidIP(const void* a, const void* b) {
    const ValidIP* va = (const ValidIP*)a;
    const ValidIP* vb = (const ValidIP*)b;
    for (int i = 0; i < 3; i++) {
        if (va->parts[i] != vb->parts[i])
            return va->parts[i] - vb->parts[i];
    }
    return 0;
}

char** filterValidAClassIPs(char** ips, int ipsSize, int* returnSize) {
    ValidIP valid[20];  // ips ≤ 15
    int cnt = 0;
    // 校验并收集合法 IP
    for (int i = 0; i < ipsSize; i++) {
        int key[3];
        if (parseValid(ips[i], key)) {
            valid[cnt].parts[0] = key[0];
            valid[cnt].parts[1] = key[1];
            valid[cnt].parts[2] = key[2];
            valid[cnt].ip = (char*)malloc(strlen(ips[i]) + 1);
            strcpy(valid[cnt].ip, ips[i]);
            cnt++;
        }
    }
    // 按后三段数值升序排序
    qsort(valid, cnt, sizeof(ValidIP), cmpValidIP);
    char** ans = (char**)malloc(cnt * sizeof(char*));
    for (int i = 0; i < cnt; i++)
        ans[i] = valid[i].ip;
    *returnSize = cnt;
