class Solution {
 public:
  vector<string> filterValidAClassIPs(vector<string>& ips) {
    // 存 (排序键, 原字符串)，便于按网段层级排序后还原 IP
    vector<pair<tuple<int, int, int>, string>> valid;
    for (auto& ip : ips) {
