/**
 * 实时流处理监控
 * 算法：前缀和 + 哈希表
 * 时间复杂度 O(n)，空间复杂度 O(n)
 *
 * @param {string[]} ops - 操作指令数组，含 "add" 与 "query"
 * @param {number[]} vals - 参数数组，与 ops 一一对应
 * @return {number[]} - 按 query 顺序返回每次查询的结果数组
 */
var monitor = function(ops, vals) {
    // 使用 Map 记录前缀和出现次数
    const cnt = new Map();
    let prefixSum = 0;
    const ans = [];

    for (let i = 0; i < ops.length; i++) {
        if (ops[i] === 'add') {
            // 当前 prefixSum 可作为新区间左端点前一位的前缀和
            cnt.set(prefixSum, (cnt.get(prefixSum) || 0) + 1);
            // 加入新的流水数据
            prefixSum += vals[i];
        } else {
            const target = vals[i];
            // 需要找 prefix[l-1] = prefixSum - target
            ans.push(cnt.get(prefixSum - target) || 0);
        }
    }

    return ans;
};
