2026年新系统题库（含题目详解）.solution:
## 解题思路

每组任务在资源 $1\ldots n$ 上建无向图：互斥对即边。两个资源池对应图的**二染色**（二分划分）：同色可同池，异色必须分池。

判定步骤（对每组独立）：

1. **自环**：若存在 $(u,u)$，直接不可行（同一资源不能与自己互斥又同池）。
2. **二分图判定**：对尚未染色的连通块 BFS/DFS 染色。若发现相邻同色，说明存在奇环，不可行；否则可行。
3. 无边或仅孤立点：任意划分均可，输出 `1`。

本质考点：**图论二分图判定**（染色法），不是贪心或并查集直接合并。

**常见假解**：

- 只检查度数 $\le 2$ 或「无三角形」→ 奇环长度 $>3$ 仍会错；
- 忽略自环 → 样例 3 第 1 组错；
- 并查集合并互斥点（等价于判能否分成 $k$ 个独立集）→ 本题固定两池，必须判二分性；
- 只检查连通块数为偶数等启发式 → 偶数环可二分、奇数环不可，与块数无关。

## 复杂度分析

设总顶点数 $V=\sum resourceCount[i]$，总边数 $E=\sum |conflicts[i]|$（题面保证 $V \le 10^5$，$E \le 2\times 10^5$）。

- 时间：$O(V+E)$，每组 BFS 染色一次；
- 空间：$O(V+E)$ 存邻接表与颜色数组。

## 代码实现

#code-switcher
```python
from collections import deque
from typing import List


class Solution:
    def canIsolateWithTwoPools(
        self, resourceCount: List[int], conflicts: List[List[List[int]]]
    ) -> List[int]:
        ans = []
        # 每组独立建图，判断是否为二分图
        for n, edges in zip(resourceCount, conflicts):
            ans.append(1 if self._bipartite(n, edges) else 0)
        return ans

    def _bipartite(self, n: int, edges: List[List[int]]) -> bool:
        # 自环：同一资源与自己互斥，两池无法划分
        for u, v in edges:
            if u == v:
                return False

        # 无向图邻接表，顶点编号 1..n
        adj = [[] for _ in range(n + 1)]
        for u, v in edges:
            adj[u].append(v)
            adj[v].append(u)

        color = [-1] * (n + 1)  # -1 表示未染色
        for start in range(1, n + 1):
            # 已染色或无边的孤立点跳过
            if color[start] != -1 or not adj[start]:
                continue
            color[start] = 0
            q = deque([start])
            while q:
                u = q.popleft()
                for v in adj[u]:
                    if color[v] == -1:
                        # 互斥边两端必须异色，对应两个资源池
                        color[v] = 1 - color[u]
                        q.append(v)
                    elif color[v] == color[u]:
                        # 相邻同色 → 奇环，不是二分图
                        return False
        return True
```

```java
import java.util.ArrayDeque;
import java.util.ArrayList;

public class Solution {
    public int[] canIsolateWithTwoPools(int[] resourceCount, int[][][] conflicts) {
        int[] ans = new int[resourceCount.length];
        // 每组独立判定能否二分到两个资源池
        for (int i = 0; i < resourceCount.length; i++)
            ans[i] = bipartite(resourceCount[i], conflicts[i]) ? 1 : 0;
        return ans;
    }

    private boolean bipartite(int n, int[][] edges) {
        // 自环直接不可行
        for (int[] e : edges)
            if (e[0] == e[1]) return false;

        // 建无向图邻接表
        ArrayList<Integer>[] adj = new ArrayList[n + 1];
        for (int i = 1; i <= n; i++) adj[i] = new ArrayList<>();
        for (int[] e : edges) {
            adj[e[0]].add(e[1]);
            adj[e[1]].add(e[0]);
        }

        int[] color = new int[n + 1];
        for (int i = 0; i <= n; i++) color[i] = -1;

        for (int start = 1; start <= n; start++) {
            if (color[start] != -1 || adj[start].isEmpty()) continue;
            color[start] = 0;
            ArrayDeque<Integer> q = new ArrayDeque<>();
            q.add(start);
            while (!q.isEmpty()) {
                int u = q.poll();
                for (int v : adj[u]) {
                    if (color[v] == -1) {
                        // 相邻顶点染成异色
                        color[v] = 1 - color[u];
                        q.add(v);
                    } else if (color[v] == color[u]) {
                        // 发现同色相邻，存在奇环
                        return false;
                    }
                }
            }
        }
        return true;
    }
}
```

```cpp
#include <deque>
#include <vector>

using namespace std;

class Solution {
 public:
  vector<int> canIsolateWithTwoPools(vector<int>& resourceCount,
                                     vector<vector<vector<int>>>& conflicts) {
    vector<int> ans;
    // 逐组判断互斥图能否二染色（两池划分）
    for (size_t i = 0; i < resourceCount.size(); i++)
      ans.push_back(bipartite(resourceCount[i], conflicts[i]) ? 1 : 0);
    return ans;
  }

 private:
  bool bipartite(int n, vector<vector<int>>& edges) {
    // 自环：资源不能与自己互斥又同池
    for (auto& e : edges)
      if (e[0] == e[1]) return false;

    // 无向邻接表
    vector<vector<int>> adj(n + 1);
    for (auto& e : edges) {
      int u = e[0], v = e[1];
      adj[u].push_back(v);
      adj[v].push_back(u);
    }

    vector<int> color(n + 1, -1);
    for (int start = 1; start <= n; start++) {
      if (color[start] != -1 || adj[start].empty()) continue;
      color[start] = 0;
      deque<int> q;
      q.push_back(start);
      while (!q.empty()) {
        int u = q.front();
        q.pop_front();
        for (int v : adj[u]) {
          if (color[v] == -1) {
            // 互斥边连接的两个资源必须分到不同池
            color[v] = 1 - color[u];
            q.push_back(v);
          } else if (color[v] == color[u]) {
            // 同色相邻，图含奇环
            return false;
          }
        }
      }
    }
    return true;
  }
};
