/**
 * 判断一组互斥图是否可以二染色（二分图检测）
 * @param {number} n 顶点数
 * @param {number[][]} edges 边列表
 * @return {boolean}
 */
function isBipartite(n, edges) {
    // 自环检查：同一资源不能和自己互斥
    for (const [u, v] of edges)
        if (u === v) return false;

    // 建无向图邻接表
    const adj = Array.from({length: n + 1}, () => []);
    for (const [u, v] of edges) {
        adj[u].push(v);
        adj[v].push(u);
    }

    // -1 未染色，0/1 两种颜色
    const color = new Array(n + 1).fill(-1);

    for (let s = 1; s <= n; s++) {
        if (color[s] !== -1 || adj[s].length === 0) continue;
        color[s] = 0;
        const q = [s];
        for (let qi = 0; qi < q.length; qi++) {
            const u = q[qi];
            for (const v of adj[u]) {
                if (color[v] === -1) {
                    // 互斥边两端必须异色
                    color[v] = 1 - color[u];
                    q.push(v);
                } else if (color[v] === color[u]) {
                    // 同色相邻 → 奇环，不是二分图
                    return false;
                }
            }
        }
    }
    return true;
}

/**
 * @param {number[]} resourceCount 各组资源总数量
 * @param {number[][][]} conflicts 每组任务的互斥资源对列表
 * @return {number[]}
 */
var canIsolateWithTwoPools = function(resourceCount, conflicts) {
    return resourceCount.map((n, i) => isBipartite(n, conflicts[i]) ? 1 : 0);
};
