struct ListNode {
    int val;
    struct ListNode* next;
};

// 判断十进制表示中是否包含 digit
int containsDigit(int x, int d) {
    if (x == 0) return d == 0;
    while (x > 0) {
        if (x % 10 == d) return 1;
        x /= 10;
    }
    return 0;
}

char* gameResult(struct ListNode* head) {
    // 第一遍：统计非淘汰节点数量（同时检查非法值）
    int total = 0;
    struct ListNode* cur = head;
    while (cur) {
        int x = cur->val;
        if (x < 0 || x > 1000000000) {
            char* r = (char*)malloc(3);
            strcpy(r, "-1");
            return r;
        }
        if (x % 3 != 0) total++;
        cur = cur->next;
    }

    // 无剩余
    if (total == 0) {
        char* r = (char*)malloc(3);
        strcpy(r, "-1");
        return r;
    }

    // 动态分配分组数组
    int* front = (int*)malloc(total * sizeof(int));
    int* middle = (int*)malloc(total * sizeof(int));
    int* back = (int*)malloc(total * sizeof(int));
    int fCnt = 0, mCnt = 0, bCnt = 0;

    // 第二遍：分组
    cur = head;
    while (cur) {
        int x = cur->val;
        if (x % 3 == 0) {
            cur = cur->next;
            continue;
        }
        if (containsDigit(x, 3)) {
            back[bCnt++] = x;
        } else if (containsDigit(x, 2)) {
            front[fCnt++] = x;
        } else {
            middle[mCnt++] = x;
        }
        cur = cur->next;
    }

    // 拼接结果字符串
    int cap = total * 12;
    char* result = (char*)malloc(cap + 1);
    result[0] = '\0';

    int first = 1;
    for (int i = 0; i < fCnt; i++) {
        if (!first) strcat(result, " ");
        char buf[16];
        sprintf(buf, "%d", front[i]);
        strcat(result, buf);
        first = 0;
    }
    for (int i = 0; i < mCnt; i++) {
        if (!first) strcat(result, " ");
        char buf[16];
        sprintf(buf, "%d", middle[i]);
        strcat(result, buf);
        first = 0;
