        // 队列中存储每个存在节点对应的深度
        queue<int> q;
        q.push(1);

        int index = 1;
        int ans = 1;

        // 按层序顺序处理每个存在的节点
        while (!q.empty()) {
            int depth = q.front();
            q.pop();

            // 处理左子节点
            if (index < nodes.size()) {
                if (nodes[index] != "#") {
                    q.push(depth + 1);
                    ans = max(ans, depth + 1);
                }
                index++;
            }

            // 处理右子节点
            if (index < nodes.size()) {
                if (nodes[index] != "#") {
                    q.push(depth + 1);
                    ans = max(ans, depth + 1);
                }
                index++;
            }
        }

        return ans;
    }
};
