            }

            nameCount[name]++;
            candidates.push_back(realName);
        }

        unordered_set<string> candidateSet(candidates.begin(), candidates.end());
        unordered_map<string, int> voteCount;

        // 统计有效选票
        for (string vote : votes) {
            if (candidateSet.count(vote)) {
                voteCount[vote]++;
            }
        }

        // 没有有效票，选举失败
        if (voteCount.empty()) {
            return "Invalid election.";
        }

        string ans = "";
        int maxVotes = -1;

        // 找出票数最多的人，票数相同取字典序更小
        for (string name : candidates) {
            int cnt = voteCount[name];

            if (cnt > maxVotes || (cnt == maxVotes && name < ans)) {
                maxVotes = cnt;
                ans = name;
            }
        }

        return ans;
    }
};
