```c
#include <limits.h>
#include <stdlib.h>

int maxChargingDemand(int n, int m, int k, int* demands) {
    const long long NEG = LLONG_MIN / 4;
    long long** dp = (long long**)malloc(n * sizeof(long long*));
    long long* best = (long long*)malloc((m + 1) * sizeof(long long));
    for (int i = 0; i < n; i++) {
        dp[i] = (long long*)malloc((m + 1) * sizeof(long long));
        for (int c = 0; c <= m; c++) dp[i][c] = NEG;
    }
    for (int c = 0; c <= m; c++) best[c] = NEG;

    long long ans = 0;
    for (int i = 0; i < n; i++) {
        // 将下标 i-k 的 DP 行并入窗口最大值
        if (i >= k) {
            for (int c = 1; c <= m; c++) {
                if (dp[i - k][c] > best[c]) best[c] = dp[i - k][c];
            }
        }
        dp[i][1] = demands[i];
        for (int c = 2; c <= m; c++) {
            if (best[c - 1] != NEG) {
                dp[i][c] = best[c - 1] + demands[i];
            }
        }
        if (dp[i][m] > ans) ans = dp[i][m];
    }

    for (int i = 0; i < n; i++) free(dp[i]);
    free(dp);
    free(best);
    return (int)ans;
}
