 * @param s 输入的表达式字符串（不含外层双引号）
 * @return 十六进制结果或 "NA"（带双引号），使用静态缓冲区
 */
char* processExpression(char* s) {
    static char buf[32];
    int n = strlen(s);

    // 长度与字符合法性检查
    if (n > 10000) { strcpy(buf, "\"NA\""); return buf; }
    for (int i = 0; i < n; i++) {
        char c = s[i];
        if (!((c >= 'a' && c <= 'z') || (c >= 'A' && c <= 'Z') ||
              (c >= '0' && c <= '9') || c == '+' || c == '-')) {
            strcpy(buf, "\"NA\""); return buf;
        }
    }
    if (n == 0) { strcpy(buf, "\"NA\""); return buf; }

    int pos = 0;

    // 解析整数：0x/0X 十六进制、0o/0O 八进制、十进制
    bool parseNumber(int* val) {
        if (pos >= n) return false;
        if (s[pos] == '0' && pos + 1 < n) {
            if (s[pos + 1] == 'x' || s[pos + 1] == 'X') {
                pos += 2; int v = 0; bool ok = false;
                while (pos < n) { int d; char c = s[pos];
                    if (c >= '0' && c <= '9') d = c - '0';
                    else if (c >= 'a' && c <= 'f') d = c - 'a' + 10;
                    else if (c >= 'A' && c <= 'F') d = c - 'A' + 10;
                    else break;
                    ok = true; v = v * 16 + d; pos++;
                }
                if (!ok || v > 999) return false;
                *val = v; return true;
            }
            if (s[pos + 1] == 'o' || s[pos + 1] == 'O') {
                pos += 2; int v = 0; bool ok = false;
                while (pos < n && s[pos] >= '0' && s[pos] <= '7')
                    { ok = true; v = v * 8 + (s[pos] - '0'); pos++; }
                if (!ok || v > 999) return false;
                *val = v; return true;
            }
        }
        if (!isdigit((unsigned char)s[pos])) return false;
        int v = 0;
        while (pos < n && isdigit((unsigned char)s[pos]))
            { v = v * 10 + (s[pos] - '0'); pos++; }
        if (v > 999) return false;
        *val = v; return true;
    }

    int result;
    if (!parseNumber(&result)) { strcpy(buf, "\"NA\""); return buf; }

    // 从左到右求值
    while (pos < n) {
        char op = s[pos++];
        if (op != '+' && op != '-') { strcpy(buf, "\"NA\""); return buf; }
        int val;
        if (!parseNumber(&val)) { strcpy(buf, "\"NA\""); return buf; }
        result = (op == '+') ? result + val : result - val;
    }
    if (pos != n) { strcpy(buf, "\"NA\""); return buf; }

    // 钳制与按位取反
    if (result > 255) result = 255;
    else if (result < -255) result = -255;
    int out = (~result) & 0xFF;
    sprintf(buf, "\"0x%02X\"", out);
    return buf;
}
