int countValidPlans(int* timestamps, int timestampsSize, int minInterval) {
    int n = timestampsSize;
    int cmp(const void* a, const void* b) {
        return (*(int*)a - *(int*)b);
    }
    qsort(timestamps, n, sizeof(int), cmp);
    int total = 1 << n;
    int ans = 0;
    for (int mask = 0; mask < total; mask++) {
        int picked[16];
        int cnt = 0;
        for (int i = 0; i < n; i++)
            if (mask & (1 << i)) picked[cnt++] = timestamps[i];
        int valid = 1;
        for (int i = 0; i < cnt && valid; i++)
            for (int j = i + 1; j < cnt; j++)
                if (picked[j] - picked[i] < minInterval) valid = 0;
        if (valid) ans++;
    }
    return ans;
}
