/**
 * @param {number} n 充电桩数量
 * @param {number[][]} cars 每辆车的 [到达时间, 充电时间, 最大等待时长]
 * @return {number} 充电失败的车辆数量
 */
var countFailedCharging = function(n, cars) {
    // 事件小根堆：按 (time, priority) 排序，0=释放 1=到达
    var events = [];
    for (var i = 0; i < cars.length; i++) {
        events.push({ time: cars[i][0], pri: 1, type: 1, idx: i });
    }
    events.sort(function(a, b) { return a.time - b.time || a.pri - b.pri; });

    // 充电桩最早可用时间的小根堆
    var piles = [];
    for (var i = 0; i < n; i++) piles.push(0);
    piles.sort(function(a, b) { return a - b; });

    var waiting = [];
    var failed = 0;

    while (events.length > 0) {
        var t = events[0].time;
        var batch = [];
        while (events.length > 0 && events[0].time === t) {
            batch.push(events.shift());
        }
        // 同时间先处理释放(pri=0)再处理到达(pri=1)
        batch.sort(function(a, b) { return a.pri - b.pri; });

        for (var i = 0; i < batch.length; i++) {
            var e = batch[i];
            if (e.type === 0) {
                piles.push(t);
                piles.sort(function(a, b) { return a - b; });
            } else {
                waiting.push(e.idx);
            }
        }

        // 把可用桩分配给等待队列中的车(FCFS)
        while (piles.length > 0 && piles[0] <= t && waiting.length > 0) {
            var carIdx = waiting[0];
            var at = cars[carIdx][0], ct = cars[carIdx][1], wt = cars[carIdx][2];
            if (t - at > wt) {
                waiting.shift();
                failed++;
                continue;
            }
            piles.shift();
            events.push({ time: t + ct, pri: 0, type: 0, idx: 0 });
            events.sort(function(a, b) { return a.time - b.time || a.pri - b.pri; });
            waiting.shift();
        }
    }

    return failed;
};
