        // dp[i][t] 表示完成 i 次查询，恰好花费 t 时间时的最大准确率
        vector<vector<int>> dp(N + 1, vector<int>(T + 1, -1));

        dp[0][0] = 0;

        // 枚举查询次数
        for (int i = 1; i <= N; i++) {
            // 枚举当前总耗时
            for (int t = 0; t <= T; t++) {
                // 枚举选择的模型
                for (int j = 0; j < m; j++) {
                    int cost = latency[j];
                    int value = accuracy[j];

                    // 如果当前时间足够，并且上一个状态可达
                    if (t >= cost && dp[i - 1][t - cost] != -1) {
                        dp[i][t] = max(dp[i][t], dp[i - 1][t - cost] + value);
                    }
                }
            }
        }

        // 总耗时不超过 T，取完成 N 次查询的最大值
        int ans = -1;
        for (int t = 0; t <= T; t++) {
            ans = max(ans, dp[N][t]);
        }

        return ans == -1 ? 0 : ans;
