```javascript
/**
 * @param {number} N 查询次数
 * @param {number} T 总时间预算
 * @param {number[]} accuracy 各模型准确率数组
 * @param {number[]} latency 各模型延迟数组
 * @return {number} 最大总准确率
 */
var maxTotalAccuracy = function(N, T, accuracy, latency) {
    var M = accuracy.length;

    // dp[i][t] 表示完成 i 次查询且恰好用时 t 时的最大准确率，-1 表示不可达
    var dp = new Array(N + 1);
    for (var i = 0; i <= N; i++) {
        dp[i] = new Array(T + 1);
        for (var t = 0; t <= T; t++)
            dp[i][t] = -1;
    }
    dp[0][0] = 0;

    // 枚举查询次数
    for (var i = 1; i <= N; i++) {
        // 枚举当前总耗时
        for (var t = 0; t <= T; t++) {
            // 枚举选择的模型
            for (var j = 0; j < M; j++) {
                var cost = latency[j];
                var value = accuracy[j];
                // 当前时间足够，且上一个状态可达
                if (t >= cost && dp[i - 1][t - cost] !== -1) {
                    var candidate = dp[i - 1][t - cost] + value;
                    if (candidate > dp[i][t])
                        dp[i][t] = candidate;
                }
            }
        }
    }

    // 在总耗时不超过 T 的前提下，取完成 N 次查询的最大值
    var ans = -1;
    for (var t = 0; t <= T; t++)
        if (dp[N][t] > ans)
            ans = dp[N][t];

    // 无法查满 N 次则返回 0
    return ans === -1 ? 0 : ans;
};
```

```c
/**
 * @param N 查询次数
 * @param T 总时间预算
 * @param accuracy 模型准确率数组
 * @param accuracySize 模型数量
 * @param latency 模型延迟数组
 * @return 最大总准确率
 */
int maxTotalAccuracy(int N, int T, int* accuracy, int accuracySize, int* latency) {
    // dp[i][t] 表示完成 i 次查询且恰好用时 t 时的最大准确率，-1 表示不可达
    int dp[11][100];
    for (int i = 0; i <= N; i++)
        for (int t = 0; t <= T; t++)
            dp[i][t] = -1;
    dp[0][0] = 0;

    // 枚举查询次数
    for (int i = 1; i <= N; i++) {
        // 枚举当前总耗时
        for (int t = 0; t <= T; t++) {
            // 枚举选择的模型
            for (int j = 0; j < accuracySize; j++) {
                int cost = latency[j];
                int value = accuracy[j];
                // 当前时间足够，且上一个状态可达
                if (t >= cost && dp[i - 1][t - cost] != -1) {
                    int candidate = dp[i - 1][t - cost] + value;
                    if (candidate > dp[i][t])
                        dp[i][t] = candidate;
                }
            }
        }
    }

    // 在总耗时不超过 T 的前提下，取完成 N 次查询的最大值
    int ans = -1;
    for (int t = 0; t <= T; t++)
        if (dp[N][t] > ans)
            ans = dp[N][t];

    // 无法查满 N 次则返回 0
    return ans == -1 ? 0 : ans;
}
