class Solution:
    class TreeNode:
        def __init__(self, val: str):
            # 保存当前节点的字符值
            self.val = val
            # 保存左子节点
            self.left = None
            # 保存右子节点
            self.right = None

    def buildAfterDelete(self, preorderStr: str, inorderStr: str, beDeletedNode: str) -> str:
        # 先检查两个字符串的基础合法性
        if not self._is_valid_string(preorderStr) or not self._is_valid_string(inorderStr):
            return ""

        # 长度必须相同
        if len(preorderStr) != len(inorderStr):
            return ""

        # 节点值必须唯一
        if len(set(preorderStr)) != len(preorderStr) or len(set(inorderStr)) != len(inorderStr):
            return ""

        # 两个遍历字符串的节点集合必须完全相同
        if set(preorderStr) != set(inorderStr):
            return ""

        # 记录每个字符在中序遍历中的位置，方便递归时快速定位根节点
        inorder_pos = {}
        for i, ch in enumerate(inorderStr):
            inorder_pos[ch] = i

        # 使用列表包装标记，方便在递归过程中修改
        ok = [True]

        # 构造二叉树
        root = self._build_tree(
            preorderStr,
            0,
            len(preorderStr) - 1,
            inorderStr,
            0,
            len(inorderStr) - 1,
            inorder_pos,
            ok
        )

        # 如果无法构造出合法二叉树，返回空串
        if not ok[0] or root is None:
            return ""

        # 删除指定节点
        self._delete_node(root, beDeletedNode)

        # 生成后序遍历结果
        ans = []
        self._postorder(root, ans)
        return "".join(ans)

    def _is_valid_string(self, s: str) -> bool:
        # 长度必须在 2 到 26 之间
        if s is None or len(s) < 2 or len(s) > 26:
            return False

        # 所有字符都必须是大写字母
        for ch in s:
            if ch < "A" or ch > "Z":
                return False
        return True

    def _build_tree(self, preorder, pre_l, pre_r, inorder, in_l, in_r, inorder_pos, ok):
        # 空区间表示空子树
        if pre_l > pre_r:
            return None

        # 前序和中序区间长度必须一致
        if pre_r - pre_l != in_r - in_l:
            ok[0] = False
            return None

        # 前序区间第一个字符是当前子树根节点
        root_val = preorder[pre_l]

        # 根节点必须出现在当前中序区间内
        if root_val not in inorder_pos:
            ok[0] = False
            return None

        mid = inorder_pos[root_val]
        if mid < in_l or mid > in_r:
            ok[0] = False
            return None

        # 根据中序位置计算左子树大小
        left_size = mid - in_l

        # 左子树大小不能超过当前前序区间剩余长度
        if pre_l + left_size > pre_r:
            ok[0] = False
            return None

        root = self.TreeNode(root_val)

        # 递归构造左子树
        root.left = self._build_tree(
            preorder,
            pre_l + 1,
            pre_l + left_size,
            inorder,
            in_l,
            mid - 1,
            inorder_pos,
            ok
        )

        # 递归构造右子树
        root.right = self._build_tree(
            preorder,
            pre_l + left_size + 1,
            pre_r,
            inorder,
            mid + 1,
            in_r,
            inorder_pos,
            ok
        )

        return root

    def _delete_node(self, root, target):
        # 待删除字符不是单个大写字母时，不进行删除
        if target is None or len(target) != 1 or target < "A" or target > "Z":
            return

        # 根节点不能删除
        if root.val == target:
            return

        # 查找目标节点及其父节点
        parent, node = self._find_parent(root, target)

        # 找不到目标节点时，不进行删除
        if node is None:
            return

        # 判断目标节点是父节点的左孩子还是右孩子
        is_left_child = parent.left is node

        # 叶子节点直接删除
        if node.left is None and node.right is None:
            if is_left_child:
                parent.left = None
            else:
                parent.right = None
            return

        # 内部节点如果是左子节点，就把它的左子树挂到父节点左侧
        if is_left_child:
            parent.left = node.left
        # 内部节点如果是右子节点，就把它的右子树挂到父节点右侧
        else:
            parent.right = node.right

    def _find_parent(self, root, target):
        # 深度优先搜索目标节点，同时记录父节点
        stack = [(None, root)]

        while stack:
            parent, node = stack.pop()
            if node is None:
                continue

            if node.val == target:
                return parent, node

            stack.append((node, node.right))
            stack.append((node, node.left))

        return None, None

    def _postorder(self, node, ans):
        # 空节点不产生输出
        if node is None:
            return

        # 后序遍历顺序：左子树、右子树、根节点
        self._postorder(node.left, ans)
        self._postorder(node.right, ans)
        ans.append(node.val)
