        // 内部节点如果是左子节点，就保留它的左子树，丢弃它和右子树
        if (isLeftChild) {
            TreeNode* keep = node->left;
            node->left = nullptr;
            clearTree(node);
            parent->left = keep;
        }
        // 内部节点如果是右子节点，就保留它的右子树，丢弃它和左子树
        else {
            TreeNode* keep = node->right;
            node->right = nullptr;
            clearTree(node);
            parent->right = keep;
        }
    }

    pair<TreeNode*, TreeNode*> findParent(TreeNode* root, char target) {
        // 深度优先搜索目标节点，同时记录父节点
        stack<pair<TreeNode*, TreeNode*>> st;
        st.push({nullptr, root});

        while (!st.empty()) {
            auto current = st.top();
            st.pop();

            TreeNode* parent = current.first;
            TreeNode* node = current.second;

            if (node == nullptr) {
                continue;
            }

            if (node->val == target) {
                return {parent, node};
            }

            st.push({node, node->right});
            st.push({node, node->left});
        }

        return {nullptr, nullptr};
    }

    void postorder(TreeNode* node, string& ans) {
        // 空节点不产生输出
        if (node == nullptr) {
            return;
        }

        // 后序遍历顺序：左子树、右子树、根节点
        postorder(node->left, ans);
        postorder(node->right, ans);
        ans.push_back(node->val);
    }

    void clearTree(TreeNode* node) {
        // 递归释放二叉树节点
        if (node == nullptr) {
            return;
        }

        clearTree(node->left);
        clearTree(node->right);
        delete node;
    }
};
