/**
 * buildAfterDelete - 构造二叉树并删除指定节点，返回后序遍历结果
 * @param {string} preorderStr 前序遍历字符串
 * @param {string} inorderStr 中序遍历字符串
 * @param {string} beDeletedNode 待删除节点字符
 * @return {string} 后序遍历结果
 */
var buildAfterDelete = function(preorderStr, inorderStr, beDeletedNode) {
    // 字符串合法性检查：长度必须在 2 到 26 之间，且只能包含大写字母
    function isValid(s) {
        if (!s || s.length < 2 || s.length > 26) return false;
        for (var i = 0; i < s.length; i++) {
            if (s[i] < 'A' || s[i] > 'Z') return false;
        }
        return true;
    }
    if (!isValid(preorderStr) || !isValid(inorderStr)) return "";

    // 长度必须相同
    if (preorderStr.length !== inorderStr.length) return "";

    // 节点值必须唯一
    function isUnique(s) {
        var seen = {};
        for (var i = 0; i < s.length; i++) {
            if (seen[s[i]]) return false;
            seen[s[i]] = true;
        }
        return true;
    }
    if (!isUnique(preorderStr) || !isUnique(inorderStr)) return "";

    // 两个字符串的节点集合必须完全相同
    var setA = {}, setB = {};
    for (var i = 0; i < preorderStr.length; i++) setA[preorderStr[i]] = true;
    for (var i = 0; i < inorderStr.length; i++) setB[inorderStr[i]] = true;
    for (var k in setA) { if (!setB[k]) return ""; setB[k] = false; }
    for (var k in setB) { if (setB[k]) return ""; }

    // 建立中序遍历位置映射
    var inorderPos = {};
    for (var i = 0; i < inorderStr.length; i++) {
        inorderPos[inorderStr[i]] = i;
    }

    var ok = true;

    // 递归构造二叉树
    function buildTree(pre, preL, preR, inOrder, inL, inR) {
        if (preL > preR) return null;
        if (preR - preL !== inR - inL) { ok = false; return null; }

        var rootVal = pre[preL];
        var mid = inorderPos[rootVal];
        if (mid === undefined || mid < inL || mid > inR) { ok = false; return null; }

        var leftSize = mid - inL;
        var root = new TreeNode(rootVal);
        root.left = buildTree(pre, preL + 1, preL + leftSize, inOrder, inL, mid - 1);
        root.right = buildTree(pre, preL + leftSize + 1, preR, inOrder, mid + 1, inR);
        return root;
    }

    var root = buildTree(preorderStr, 0, preorderStr.length - 1, inorderStr, 0, inorderStr.length - 1);
    if (!ok || !root) return "";

    // 删除指定节点
    var target = beDeletedNode;
    if (target && target.length === 1 && target >= 'A' && target <= 'Z' && root.val !== target) {
        // 查找目标节点及其父节点
        function findParent(root, target) {
            var stack = [[null, root]];
            while (stack.length > 0) {
                var pair = stack.pop();
                var parent = pair[0], node = pair[1];
                if (!node) continue;
                if (node.val === target) return { parent: parent, node: node };
                stack.push([node, node.right]);
                stack.push([node, node.left]);
            }
            return { parent: null, node: null };
        }

        var res = findParent(root, target);
        var parent = res.parent, node = res.node;

        if (node) {
            var isLeftChild = parent.left === node;
            if (!node.left && !node.right) {
                // 叶子节点：直接删除
                if (isLeftChild) parent.left = null;
                else parent.right = null;
            } else {
                // 内部节点：保留对应子树
                if (isLeftChild) parent.left = node.left;
                else parent.right = node.right;
            }
        }
    }

    // 后序遍历
    function postorder(node, arr) {
        if (!node) return;
        postorder(node.left, arr);
        postorder(node.right, arr);
        arr.push(node.val);
    }

    var result = [];
    postorder(root, result);
    return result.join('');
};
