```c
#include <stdlib.h>
#include <string.h>
#include <stdbool.h>

// 二叉树节点结构
typedef struct TreeNode {
    char val;
    struct TreeNode* left;
    struct TreeNode* right;
} TreeNode;

// 创建新节点
TreeNode* createNode(char val) {
    TreeNode* node = (TreeNode*)malloc(sizeof(TreeNode));
    node->val = val;
    node->left = NULL;
    node->right = NULL;
    return node;
}

// 递归释放二叉树
void freeTree(TreeNode* node) {
    if (node == NULL) return;
    freeTree(node->left);
    freeTree(node->right);
    free(node);
}

// 查找目标节点及其父节点（栈式迭代 DFS）
void findParent(TreeNode* root, char target, TreeNode** parent, TreeNode** node) {
    TreeNode* stack[100];
    TreeNode* pstack[100];
    int top = 0;
    stack[top] = root;
    pstack[top] = NULL;
    top++;

    while (top > 0) {
        top--;
        TreeNode* cur = stack[top];
        TreeNode* par = pstack[top];
        if (cur == NULL) continue;
        if (cur->val == target) { *parent = par; *node = cur; return; }
        stack[top] = cur->right; pstack[top] = cur; top++;
        stack[top] = cur->left; pstack[top] = cur; top++;
    }
    *parent = NULL; *node = NULL;
}

// 删除指定节点
void deleteNode(TreeNode* root, const char* beDeletedNode) {
    if (beDeletedNode == NULL || strlen(beDeletedNode) != 1) return;
    char target = beDeletedNode[0];
    if (target < 'A' || target > 'Z') return;
    if (root->val == target) return;

    TreeNode *parent = NULL, *node = NULL;
    findParent(root, target, &parent, &node);
    if (node == NULL) return;

    bool isLeftChild = (parent->left == node);

    if (node->left == NULL && node->right == NULL) {
        // 叶子节点：直接删除
        if (isLeftChild) parent->left = NULL;
        else parent->right = NULL;
        free(node);
        return;
    }

    // 内部节点：保留对应子树，丢弃该节点
    if (isLeftChild) {
        parent->left = node->left;
        node->left = NULL;
    } else {
        parent->right = node->right;
        node->right = NULL;
    }
    freeTree(node);
}

// 后序遍历
void postorder(TreeNode* node, char* buf, int* idx) {
    if (node == NULL) return;
    postorder(node->left, buf, idx);
    postorder(node->right, buf, idx);
    buf[(*idx)++] = node->val;
}

// 合法性检查
bool isValidString(const char* s) {
    if (s == NULL) return false;
    int len = strlen(s);
    if (len < 2 || len > 26) return false;
    for (int i = 0; i < len; i++)
        if (s[i] < 'A' || s[i] > 'Z') return false;
    return true;
}

bool isUniqueStr(const char* s) {
    bool seen[128] = {false};
    for (int i = 0; s[i]; i++) {
        unsigned char c = (unsigned char)s[i];
        if (seen[c]) return false;
        seen[c] = true;
    }
    return true;
}

bool sameSet(const char* a, const char* b) {
    bool setA[128] = {false}, setB[128] = {false};
    for (int i = 0; a[i]; i++) setA[(unsigned char)a[i]] = true;
    for (int i = 0; b[i]; i++) setB[(unsigned char)b[i]] = true;
    for (int i = 0; i < 128; i++)
        if (setA[i] != setB[i]) return false;
    return true;
}

static bool buildOk;

// 递归构造二叉树
TreeNode* buildTree(const char* preorder, int preL, int preR,
                    const char* inorder, int inL, int inR, int* inorderPos) {
    if (preL > preR) return NULL;
    if (preR - preL != inR - inL) { buildOk = false; return NULL; }

    char rootVal = preorder[preL];
    int mid = inorderPos[(unsigned char)rootVal];
    if (mid < inL || mid > inR || mid < 0) { buildOk = false; return NULL; }

    int leftSize = mid - inL;
    TreeNode* root = createNode(rootVal);
    root->left = buildTree(preorder, preL + 1, preL + leftSize, inorder, inL, mid - 1, inorderPos);
    root->right = buildTree(preorder, preL + leftSize + 1, preR, inorder, mid + 1, inR, inorderPos);
    return root;
}

/**
 * buildAfterDelete - 构造二叉树并删除指定节点，返回后序遍历结果
 */
char* buildAfterDelete(char* preorderStr, char* inorderStr, char* beDeletedNode) {
    if (!isValidString(preorderStr) || !isValidString(inorderStr))
        return strdup("");
    if (strlen(preorderStr) != strlen(inorderStr)) return strdup("");
    if (!isUniqueStr(preorderStr) || !isUniqueStr(inorderStr)) return strdup("");
    if (!sameSet(preorderStr, inorderStr)) return strdup("");

    int inorderPos[256], n = strlen(inorderStr);
    for (int i = 0; i < 256; i++) inorderPos[i] = -1;
    for (int i = 0; i < n; i++) inorderPos[(unsigned char)inorderStr[i]] = i;

    buildOk = true;
    TreeNode* root = buildTree(preorderStr, 0, n - 1, inorderStr, 0, n - 1, inorderPos);
    if (!buildOk || root == NULL) return strdup("");

    deleteNode(root, beDeletedNode);

    char* ans = (char*)malloc(n + 1);
    int idx = 0;
    postorder(root, ans, &idx);
    ans[idx] = '\0';
    freeTree(root);
    return ans;
}
