 */
var getMaxDivisibleNumber = function(inputStr, inputDivisor) {
    // 校验输入合法性
    if (typeof inputStr !== 'string' || inputStr.length < 1 || inputStr.length > 10000) {
        return -1;
    }
    if (!Number.isInteger(inputDivisor) || inputDivisor < 1 || inputDivisor > 99) {
        return -1;
    }

    // 检查是否有非法字符，只允许 A-Z、a-z、0-9
    if (!/^[A-Za-z0-9]+$/.test(inputStr)) {
        return -1;
    }

    // 提取所有连续数字串
    const matches = inputStr.match(/\d+/g);
    if (!matches) return -1;

    let maxDivisible = -1;

    for (const numStr of matches) {
        // 解析为整数
        const val = parseInt(numStr, 10);

        // 检查数值范围是否合法
        if (val < 0 || val > 999) {
            return -1;
        }

        // 判断能否被除数整除，更新最大值
        if (val % inputDivisor === 0) {
            if (val > maxDivisible) {
                maxDivisible = val;
            }
        }
    }

    return maxDivisible;
};
