#include <string.h>
#include <stdbool.h>

int getMaxDivisibleNumber(char* inputStr, int inputDivisor) {
    int n = (int)strlen(inputStr);
    // 校验字符串长度和除数范围
    if (n < 1 || n > 10000) {
        return -1;
    }
    if (inputDivisor < 1 || inputDivisor > 99) {
        return -1;
    }

    int answer = -1;
    int i = 0;

    while (i < n) {
        char ch = inputStr[i];

        // 合法字符校验：仅限字母或数字
        if (!((ch >= '0' && ch <= '9') ||
              (ch >= 'a' && ch <= 'z') ||
              (ch >= 'A' && ch <= 'Z'))) {
            return -1; // 出现非法字符
        }

        // 字母直接跳过
        if (ch < '0' || ch > '9') {
            i++;
            continue;
        }

        // 数字串开始，读取完整连续数字
        int value = 0;
        int significantCount = 0; // 有效位数（不含前导零）
        bool hasNonZero = false;

        while (i < n && inputStr[i] >= '0' && inputStr[i] <= '9') {
            int digit = inputStr[i] - '0';
            if (digit != 0) {
                hasNonZero = true;
                significantCount++;
                value = value * 10 + digit;
                // 超过范围视为非法
                if (significantCount > 3 || value > 999) {
                    return -1;
                }
            } else {
                // 非前导零才累计有效位数
                if (hasNonZero) {
                    significantCount++;
                    value = value * 10;
                    if (significantCount > 3 || value > 999) {
                        return -1;
                    }
                }
            }
            i++;
        }

        // 全是前导零，值为 0
        if (!hasNonZero) {
            value = 0;
        }

        // 能被整除则更新答案
        if (value % inputDivisor == 0) {
            if (value > answer) {
                answer = value;
            }
        }
    }

    return answer;
}
