int** processPackets(int n, int k, char** packets, int packetsSize, int* returnSize) {
    int m = (n < packetsSize) ? n : packetsSize;
    *returnSize = 0;
    if (k <= 0 || k > m) return NULL;

    int* ids = malloc(sizeof(int) * m);
    long long* priorities = malloc(sizeof(long long) * m);
    for (int i = 0; i < m; i++) {
        char* colon = strchr(packets[i], ':');
        ids[i] = atoi(packets[i]);
        priorities[i] = colon ? atoll(colon + 1) : 0;
    }

    int* nextGreater = malloc(sizeof(int) * m);
    for (int i = 0; i < m; i++) nextGreater[i] = -1;

    int* stack = malloc(sizeof(int) * m);
    int top = -1;
    for (int i = 0; i < m; i++) {
        while (top >= 0 && priorities[stack[top]] < priorities[i]) {
            nextGreater[stack[top--]] = i;
        }
        stack[++top] = i;
    }

    int maxWindows = m - k + 1;
    int** ans = malloc(sizeof(int*) * maxWindows);

    for (int start = 0; start + k <= m; start++) {
        int end = start + k - 1;
        int* window = calloc(k, sizeof(int));
        int wc = 0;
        for (int i = start; i <= end; i++) {
            int j = nextGreater[i];
            if (j != -1 && j <= end) window[wc++] = ids[j];
        }
        if (wc > 0) ans[(*returnSize)++] = window;
        else free(window);
    }

    free(stack);
    free(nextGreater);
    free(priorities);
    free(ids);
    return ans;
}
