class Solution {
public:
    vector<vector<string>> queryFriends(vector<vector<string>>& nodes,
                                        vector<vector<string>>& relations,
                                        string myId,
                                        int maxHop) {
        // 最大跳数按题意限制到 100
        int hopLimit = min(maxHop, 100);

        // 建立用户 ID 到兴趣集合的映射
        unordered_map<string, unordered_set<string>> interests;
        for (auto& row : nodes) {
            if (row.empty()) {
                continue;
            }

            string uid = row[0];
            unordered_set<string> set;

            for (int i = 1; i < (int)row.size(); i++) {
                set.insert(row[i]);
            }

            interests[uid] = set;
        }

        // 起始用户一定存在，直接取出它的兴趣集合
        unordered_set<string>& myInterests = interests[myId];

        // 初始化邻接表，只给存在的用户建表
        unordered_map<string, vector<string>> graph;
        for (auto& kv : interests) {
            graph[kv.first] = vector<string>();
        }

        // 建立有向图，非法关系直接忽略
        for (auto& edge : relations) {
            if (edge.size() < 2) {
                continue;
            }

            string a = edge[0];
            string b = edge[1];

            if (interests.count(a) && interests.count(b)) {
                graph[a].push_back(b);
            }
        }

        // BFS 计算从 myId 到其他用户的最短距离
        unordered_map<string, int> dist;
        queue<string> q;

        dist[myId] = 0;
        q.push(myId);

        while (!q.empty()) {
            string cur = q.front();
            q.pop();

            int curDist = dist[cur];

            // 已经达到最大跳数时，不再继续向外扩展
            if (curDist == hopLimit) {
                continue;
            }

            for (const string& nxt : graph[cur]) {
                if (!dist.count(nxt)) {
                    dist[nxt] = curDist + 1;
                    q.push(nxt);
                }
            }
        }

        // 保存排序键和输出行：最短距离、整数 ID、结果行
        vector<tuple<int, int, vector<string>>> items;

        // 遍历所有可达用户，筛选有共同兴趣的用户
        for (auto& kv : dist) {
            string uid = kv.first;

            if (uid == myId) {
                continue;
            }

            // 计算共同兴趣
            vector<string> common;
            for (const string& tag : myInterests) {
                if (interests[uid].count(tag)) {
                    common.push_back(tag);
                }
            }

            if (common.empty()) {
                continue;
            }

            // 共同兴趣按 ASCII 码序排序
            sort(common.begin(), common.end());

            vector<string> row;
            row.push_back(uid);
            for (const string& tag : common) {
                row.push_back(tag);
            }

            items.push_back(make_tuple(kv.second, stoi(uid), row));
        }

        // 先按最短距离排序，再按 ID 整数值排序
        sort(items.begin(), items.end(), [](const auto& a, const auto& b) {
            if (get<0>(a) != get<0>(b)) {
                return get<0>(a) < get<0>(b);
            }
            return get<1>(a) < get<1>(b);
        });

        // 只返回题目要求的二维数组
        vector<vector<string>> answer;
        for (auto& item : items) {
            answer.push_back(get<2>(item));
        }

        return answer;
    }
};
