 * @param {string} myId - 起始用户ID
 * @param {number} maxHop - 最大跳数
 * @return {string[][]} - 满足条件的用户ID及共同兴趣列表
 */
var queryFriends = function(nodes, relations, myId, maxHop) {
    // 最大跳数限制到 100
    let hopLimit = Math.min(maxHop, 100);

    // 建立用户到兴趣集合的映射
    let interests = new Map();
    for (let row of nodes) {
        let uid = row[0];
        interests.set(uid, new Set(row.slice(1)));
    }

    // 起始用户兴趣集合
    let myInterests = interests.get(myId);

    // 建立有向邻接表
    let graph = new Map();
    for (let uid of interests.keys()) graph.set(uid, []);
    for (let edge of relations) {
        let a = edge[0], b = edge[1];
        if (interests.has(a) && interests.has(b)) {
            graph.get(a).push(b);
        }
    }

    // BFS 计算最短距离
    let dist = new Map();
    let queue = [myId];
    dist.set(myId, 0);
    let head = 0;
    while (head < queue.length) {
        let cur = queue[head++];
        let curDist = dist.get(cur);
        if (curDist === hopLimit) continue;
        for (let nxt of graph.get(cur)) {
            if (!dist.has(nxt)) {
                dist.set(nxt, curDist + 1);
                queue.push(nxt);
            }
        }
    }

    // 收集满足条件的用户
    let items = [];
    for (let [uid, d] of dist) {
        if (uid === myId) continue;

        // 计算共同兴趣
        let common = [];
        for (let tag of myInterests) {
            if (interests.get(uid).has(tag)) {
                common.push(tag);
            }
        }
        if (common.length === 0) continue;

        // 共同兴趣按 ASCII 码序排序
        common.sort();

        items.push({
            dist: d,
            id: parseInt(uid),
            row: [uid, ...common]
        });
    }

    // 按距离排序，距离相同按 ID 整数值排序
    items.sort((a, b) => a.dist !== b.dist ? a.dist - b.dist : a.id - b.id);

    return items.map(item => item.row);
};
```
