```python
class Solution:
    def findIsolatedStations(self, n, sources, pipes):
        # 建立邻接表，graph[x] 表示水可以从 x 直接流向的水站列表
        graph = [[] for _ in range(n)]

        # 根据管道类型建图
        for u, v, typ in pipes:
            if typ == 0:
                # 单向管道：水只能从 u 流向 v
                graph[u].append(v)
            else:
                # 双向管道：水可以在 u 和 v 之间双向流动
                graph[u].append(v)
                graph[v].append(u)

        # visited[i] 表示 i 号水站是否可以从某个源头站获得供水
        visited = [False] * n

        # 使用队列进行广度优先搜索，所有源头站同时入队
        queue = []
        head = 0

        for s in sources:
            # 源头站一定有水，若尚未访问则加入搜索队列
            if 0 <= s < n and not visited[s]:
                visited[s] = True
                queue.append(s)

        # 从所有源头站出发，沿着水流方向扩展
        while head < len(queue):
            cur = queue[head]
            head += 1

            # 当前水站有水，则它能流到的下一批水站也可以获得供水
            for nxt in graph[cur]:
                if not visited[nxt]:
                    visited[nxt] = True
                    queue.append(nxt)

        # 按编号从小到大收集没有供水的水站
        ans = []
        for i in range(n):
            if not visited[i]:
                ans.append(i)

        return ans
