class Solution {
public:
    vector<int> findIsolatedStations(int n, vector<int>& sources, vector<vector<int>>& pipes) {
        // 建立邻接表，graph[u] 保存所有可以由 u 直接供水到达的水站
        vector<vector<int>> graph(n);

        // 根据管道类型加入有向边
        for (vector<int>& pipe : pipes) {
            int u = pipe[0];
            int v = pipe[1];
            int typ = pipe[2];

            if (typ == 0) {
                // 单向管道：水只能从 u 流向 v
                graph[u].push_back(v);
            } else {
                // 双向管道：水可以从 u 到 v，也可以从 v 到 u
                graph[u].push_back(v);
                graph[v].push_back(u);
            }
        }

        // visited[i] 表示 i 号水站是否已经确认可以获得供水
        vector<int> visited(n, 0);

        // 使用数组模拟队列，避免递归导致栈空间风险
        vector<int> queue(n);
        int head = 0;
        int tail = 0;

        // 所有源头站都是搜索起点
        for (int s : sources) {
            if (0 <= s && s < n && !visited[s]) {
                visited[s] = 1;
                queue[tail++] = s;
            }
        }

        // 广度优先搜索：从有水的水站出发，沿着管道方向继续供水
        while (head < tail) {
            int cur = queue[head++];

            for (int nxt : graph[cur]) {
                if (!visited[nxt]) {
                    visited[nxt] = 1;
                    queue[tail++] = nxt;
                }
            }
        }

        // 按编号从小到大收集没有被访问到的水站
        vector<int> ans;
        for (int i = 0; i < n; i++) {
            if (!visited[i]) {
                ans.push_back(i);
            }
        }

        return ans;
    }
};
