#include <algorithm>
#include <set>
#include <string>
#include <vector>
using namespace std;

class Solution {
public:
    vector<string> FindNextKeywords(vector<string> &commands, string prefix) {
        set<string> seen;  // 有序集合，天然字典序
        for (const string &raw : commands) {
            // 去掉首尾空格
            size_t b = raw.find_first_not_of(' ');
            if (b == string::npos) continue;
            size_t e = raw.find_last_not_of(' ');
            string s = raw.substr(b, e - b + 1);
            // 检查前缀
            if (s.size() < prefix.size() || s.compare(0, prefix.size(), prefix) != 0) continue;
            // 去除前缀并再次去掉首尾空格
            string rest = s.substr(prefix.size());
            b = rest.find_first_not_of(' ');
            if (b == string::npos) continue;
            e = rest.find_last_not_of(' ');
            rest = rest.substr(b, e - b + 1);
            // 提取第一个关键字
            size_t sp = rest.find(' ');
            string word = (sp == string::npos) ? rest : rest.substr(0, sp);
            if (!word.empty()) seen.insert(word);
        }
        // 转为向量返回
        return vector<string>(seen.begin(), seen.end());
    }
};
