#include <string.h>
#include <stdlib.h>
#include <stdbool.h>

// 字符串比较函数，用于 qsort 排序
static int _cmpstr(const void* a, const void* b) {
    return strcmp(*(const char**)a, *(const char**)b);
}

char** FindNextKeywords(char** commands, int commandsSize, char* prefix, int* returnSize) {
    char** result = (char**)malloc(commandsSize * sizeof(char*));
    int resultCount = 0;
    int prefixLen = strlen(prefix);

    for (int i = 0; i < commandsSize; i++) {
        // 跳过命令行首部空格
        const char* s = commands[i];
        while (*s == ' ') s++;
        // 检查是否以前缀开头
        if (strncmp(s, prefix, prefixLen) != 0) continue;
        // 前缀之后的剩余部分，去掉首部空格
        const char* rest = s + prefixLen;
        while (*rest == ' ') rest++;
        if (*rest == '\0') continue;
        // 提取第一个关键字（到下一个空格或字符串末尾）
        const char* p = rest;
        while (*p != '\0' && *p != ' ') p++;
        int wordLen = p - rest;
        // 去重检查
        bool duplicate = false;
        for (int j = 0; j < resultCount; j++) {
            if (strlen(result[j]) == (size_t)wordLen &&
                strncmp(result[j], rest, wordLen) == 0) {
                duplicate = true;
                break;
            }
        }
        if (duplicate) continue;
        // 添加新关键字
        result[resultCount] = (char*)malloc(wordLen + 1);
        strncpy(result[resultCount], rest, wordLen);
        result[resultCount][wordLen] = '\0';
        resultCount++;
    }
    // 按字典序排序
    qsort(result, resultCount, sizeof(char*), _cmpstr);
    *returnSize = resultCount;
    return result;
}
