2026年新系统题库（含题目详解）.solution:
## 解题思路

一次优化操作选择的是当前所有正数货物中某一个连续段，并让这一段全部减少 1。可以把数组看成柱状图：在某个高度层 `h` 上，所有 `goodProceeTime[i] >= h` 的位置会形成若干个连续段，每个连续段长度就是在这一层执行一次优化能减少的总处理时间。

因此，问题转化为：统计所有高度层上的正连续段长度，从中选择最多 `optimize` 个最大的长度，使总减少量最大，最终答案为原始总和减去最大减少量。

为了高效统计这些长度，按处理时间从高到低激活位置，并用并查集维护当前高度层的连续段。每个连通段在若干个连续高度层中保持不变，记录它的起始高度；当它因为更低高度的新位置加入而合并时，先结算旧连续段贡献了多少次对应长度。最后得到 `countByLen[len]`，表示长度为 `len` 的优化收益出现了多少次。再从大到小取前 `optimize` 个收益即可。

## 复杂度分析

设数组长度为 `n`，最大处理时间为 `V`。

每个位置只会被激活一次，每次最多与左右相邻位置合并，所有并查集操作总复杂度近似为 `O(n)`；按高度遍历需要 `O(V)`，最后按长度统计需要 `O(n)`。

时间复杂度：`O(n + V)`。

空间复杂度：`O(n + V)`。

在本题约束 `n <= 10^5`、`goodProceeTime[i] <= 10^5` 下可以稳定通过。

## 代码实现

#code-switcher
```python
from typing import List

class Solution:
    def minProcessTime(self, goodProceeTime: List[int], optimize: int) -> int:
        n = len(goodProceeTime)
        total = sum(goodProceeTime)
        if optimize <= 0 or total == 0:
            return total

        # 按高度分组，后续从高到低激活货物位置
        max_value = max(goodProceeTime, default=0)
        by_height = [[] for _ in range(max_value + 1)]
        for i, value in enumerate(goodProceeTime):
            if value > 0:
                by_height[value].append(i)

        # 并查集初始化
        parent = list(range(n))
        size = [1] * n
        start_height = [0] * n
        active = [False] * n
        count_by_len = [0] * (n + 1)

        # 查找并查集的根
        def find(x: int) -> int:
            while parent[x] != x:
                parent[x] = parent[parent[x]]
                x = parent[x]
            return x

        # 结算连续段在高度变化间隔内的收益贡献
        def close_component(root: int, h: int) -> None:
            times = start_height[root] - h
            if times > 0:
                count_by_len[size[root]] += times

        # 合并两个连续段
        def merge(a: int, b: int, h: int) -> int:
            ra, rb = find(a), find(b)
            if ra == rb:
                return ra
            # 合并前结算旧段贡献
            close_component(ra, h)
            close_component(rb, h)
            if size[ra] < size[rb]:
                ra, rb = rb, ra
            parent[rb] = ra
            size[ra] += size[rb]
            start_height[ra] = h
            return ra

        # 从高到低逐层激活
        for h in range(max_value, 0, -1):
            for idx in by_height[h]:
                active[idx] = True
                parent[idx] = idx
                size[idx] = 1
                start_height[idx] = h
                root = idx
                if idx > 0 and active[idx - 1]:
                    root = merge(root, idx - 1, h)
                if idx + 1 < n and active[idx + 1]:
                    root = merge(root, idx + 1, h)

        # 收尾：处理未结算的段
        for i in range(n):
            if active[i] and find(i) == i:
                close_component(i, 0)

        # 从大到小选取最优操作
        saved = 0
        left = optimize
        for length in range(n, 0, -1):
            if left == 0:
                break
            take = min(left, count_by_len[length])
            saved += take * length
            left -= take
        return total - saved
```

```java
import java.util.*;

class Solution {
    private int[] parent;
    private int[] size;
    private int[] startHeight;
    private long[] countByLen;

    public long minProcessTime(int[] goodProceeTime, int optimize) {
        int n = goodProceeTime.length;
        long total = 0;
        int maxValue = 0;
        for (int value : goodProceeTime) {
            total += value;
            maxValue = Math.max(maxValue, value);
        }
        if (optimize <= 0 || total == 0) {
            return total;
        }

        // 按高度分组
        List<Integer>[] byHeight = new ArrayList[maxValue + 1];
        for (int i = 0; i <= maxValue; i++) {
            byHeight[i] = new ArrayList<>();
        }
        for (int i = 0; i < n; i++) {
            if (goodProceeTime[i] > 0) {
                byHeight[goodProceeTime[i]].add(i);
            }
        }

        // 并查集初始化
        parent = new int[n];
        size = new int[n];
        startHeight = new int[n];
        countByLen = new long[n + 1];
        boolean[] active = new boolean[n];
        Arrays.fill(size, 1);

        // 从高到低遍历
        for (int h = maxValue; h >= 1; h--) {
            for (int idx : byHeight[h]) {
                active[idx] = true;
                parent[idx] = idx;
                size[idx] = 1;
                startHeight[idx] = h;
                int root = idx;
                if (idx > 0 && active[idx - 1]) {
                    root = merge(root, idx - 1, h);
                }
                if (idx + 1 < n && active[idx + 1]) {
                    root = merge(root, idx + 1, h);
                }
            }
        }

        // 收尾结算
        for (int i = 0; i < n; i++) {
            if (active[i] && find(i) == i) {
                closeComponent(i, 0);
            }
        }

        // 选取最大收益的段
        long saved = 0;
        long left = optimize;
        for (int len = n; len >= 1 && left > 0; len--) {
            long take = Math.min(left, countByLen[len]);
            saved += take * len;
            left -= take;
        }
        return total - saved;
    }

    private int find(int x) {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }

    // 结算连续段在高度变化间隔内的收益贡献
    private void closeComponent(int root, int h) {
        long times = (long) startHeight[root] - h;
        if (times > 0) {
            countByLen[size[root]] += times;
        }
    }

    // 合并两个连续段
    private int merge(int a, int b, int h) {
        int ra = find(a);
        int rb = find(b);
        if (ra == rb) {
            return ra;
        }
        closeComponent(ra, h);
        closeComponent(rb, h);
        if (size[ra] < size[rb]) {
            int tmp = ra;
            ra = rb;
            rb = tmp;
        }
        parent[rb] = ra;
        size[ra] += size[rb];
        startHeight[ra] = h;
        return ra;
    }
}
