static long long _countByLen[100001];

static int _find(int x) {
    while (_parent[x] != x) {
        _parent[x] = _parent[_parent[x]];
        x = _parent[x];
    }
    return x;
}

// 结算连续段在高度变化间隔内的收益贡献
static void _closeComponent(int root, int h) {
    long long times = (long long)_startHeight[root] - h;
    if (times > 0) {
        _countByLen[_size[root]] += times;
    }
}

// 合并两个连续段
static int _merge(int a, int b, int h) {
    int ra = _find(a), rb = _find(b);
    if (ra == rb) return ra;
    _closeComponent(ra, h);
    _closeComponent(rb, h);
    if (_size[ra] < _size[rb]) {
        int tmp = ra; ra = rb; rb = tmp;
    }
    _parent[rb] = ra;
    _size[ra] += _size[rb];
    _startHeight[ra] = h;
    return ra;
}

long long minProcessTime(int* goodProceeTime, int goodProceeTimeSize, int optimize) {
    int n = goodProceeTimeSize;
    long long total = 0;
    int maxVal = 0;
    for (int i = 0; i < n; i++) {
        total += goodProceeTime[i];
        if (goodProceeTime[i] > maxVal) maxVal = goodProceeTime[i];
    }
    if (optimize <= 0 || total == 0) return total;

    // 按高度分组
    int** byHeight = (int**)calloc(maxVal + 1, sizeof(int*));
    int* byHeightCnt = (int*)calloc(maxVal + 1, sizeof(int));
    for (int i = 0; i < n; i++) {
        if (goodProceeTime[i] > 0) byHeightCnt[goodProceeTime[i]]++;
    }
    for (int h = 1; h <= maxVal; h++) {
        if (byHeightCnt[h] > 0) {
            byHeight[h] = (int*)malloc(byHeightCnt[h] * sizeof(int));
            byHeightCnt[h] = 0;
        }
    }
    for (int i = 0; i < n; i++) {
        int v = goodProceeTime[i];
        if (v > 0) byHeight[v][byHeightCnt[v]++] = i;
    }

    // 并查集初始化
    for (int i = 0; i < n; i++) {
        _active[i] = 0;
    }
    for (int i = 0; i <= n; i++) {
        _countByLen[i] = 0;
    }

    // 从高到低逐层激活
    for (int h = maxVal; h >= 1; h--) {
        for (int j = 0; j < byHeightCnt[h]; j++) {
            int idx = byHeight[h][j];
            _active[idx] = 1;
            _parent[idx] = idx;
            _size[idx] = 1;
            _startHeight[idx] = h;
            int root = idx;
            if (idx > 0 && _active[idx - 1]) root = _merge(root, idx - 1, h);
            if (idx + 1 < n && _active[idx + 1]) root = _merge(root, idx + 1, h);
        }
    }

    // 收尾
    for (int i = 0; i < n; i++) {
        if (_active[i] && _find(i) == i) _closeComponent(i, 0);
    }

    // 选取最大收益的段
    long long saved = 0;
    long long left = optimize;
    for (int len = n; len >= 1 && left > 0; len--) {
        long long take = left < _countByLen[len] ? left : _countByLen[len];
        saved += take * len;
        left -= take;
    }

    // 清理
    for (int h = 1; h <= maxVal; h++) {
        free(byHeight[h]);
    }
    free(byHeight);
    free(byHeightCnt);

    return total - saved;
}
