#include <string.h>
#include <stdlib.h>

typedef struct Node {
    char* desc;
    struct Node* prev;
    struct Node* next;
} Node;

// 释放链表内存
static void _freeList(Node* head) {
    Node* p = head;
    while (p) {
        Node* tmp = p;
        p = p->next;
        free(tmp->desc);
        free(tmp);
    }
}

char* execute_command(char*** command, int commandSize, int* commandColSize) {
    // 创建虚拟头节点，表示初始状态
    Node* head = (Node*)malloc(sizeof(Node));
    head->desc = (char*)malloc(1);
    head->desc[0] = '\0';
    head->prev = NULL;
    head->next = NULL;

    Node* cur = head;

    for (int i = 0; i < commandSize; i++) {
        char* op = command[i][0];
        if (strcmp(op, "execute") == 0) {
            // 清除当前之后的所有 redo 历史
            Node* p = cur->next;
            while (p) {
                Node* tmp = p;
                p = p->next;
                free(tmp->desc);
                free(tmp);
            }
            cur->next = NULL;

            // 创建新节点保存操作描述
            Node* newNode = (Node*)malloc(sizeof(Node));
            newNode->desc = (char*)malloc(strlen(command[i][1]) + 1);
            strcpy(newNode->desc, command[i][1]);
            newNode->prev = cur;
            newNode->next = NULL;
            cur->next = newNode;
            cur = newNode;
        } else if (strcmp(op, "undo") == 0) {
            // 回退操作
            if (cur == head) {
                char* msg = (char*)malloc(13);
                strcpy(msg, "undo failed");
                _freeList(head);
                return msg;
            }
            cur = cur->prev;
        } else if (strcmp(op, "redo") == 0) {
            // 重做操作
            if (cur->next == NULL) {
                char* msg = (char*)malloc(13);
                strcpy(msg, "redo failed");
                _freeList(head);
                return msg;
            }
            cur = cur->next;
        }
    }

    // 返回当前操作描述
    char* result = (char*)malloc(strlen(cur->desc) + 1);
    strcpy(result, cur->desc);
    _freeList(head);
    return result;
}
