#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    /**
     * 代码中的类名、方法名、参数名已经指定，请勿修改，直接返回方法规定的值即可
     *
     * 找出所有出现次数大于等于 3 次的日志标识
     * @param logs string字符串vector 日志标识数组
     * @return string字符串vector
     */
    vector<string> findAnomalyLogs(vector<string>& logs) {
        unordered_map<string, int> cnt;
        unordered_map<string, int> first;

        // 统计每个日志标识出现次数，并记录首次出现位置
        for (int i = 0; i < (int)logs.size(); i++) {
            string s = logs[i];
            cnt[s]++;
            if (first.find(s) == first.end()) {
                first[s] = i;
            }
        }

        vector<string> ans;

        // 筛选出现次数大于等于 3 次的日志标识
        for (auto &p : cnt) {
            if (p.second >= 3) {
                ans.push_back(p.first);
            }
        }

        // 按出现次数降序，首次出现位置升序排序
        sort(ans.begin(), ans.end(), [&](const string& a, const string& b) {
            if (cnt[a] != cnt[b]) {
                return cnt[a] > cnt[b];
            }
            return first[a] < first[b];
        });

        return ans;
    }
};
