```c
#include <string.h>
#include <stdlib.h>

typedef struct {
    char* name;
    int count;
    int firstIdx;
} LogEntry;

// 比较函数：出现次数降序，首次出现位置升序
static int _cmp(const void* a, const void* b) {
    const LogEntry* x = (const LogEntry*)a;
    const LogEntry* y = (const LogEntry*)b;
    if (x->count != y->count) return y->count - x->count;
    return x->firstIdx - y->firstIdx;
}

char** findAnomalyLogs(char** logs, int logsSize, int* returnSize) {
    // 建立日志条目数组以统计次数
    LogEntry* entries = (LogEntry*)malloc(logsSize * sizeof(LogEntry));
    int entryCount = 0;

    for (int i = 0; i < logsSize; i++) {
        int found = -1;
        for (int j = 0; j < entryCount; j++) {
            if (strcmp(entries[j].name, logs[i]) == 0) {
                found = j;
                break;
            }
        }
        if (found == -1) {
            entries[entryCount].name = logs[i];
            entries[entryCount].count = 1;
            entries[entryCount].firstIdx = i;
            entryCount++;
        } else {
            entries[found].count++;
        }
    }

    // 筛选出现次数 >= 3 次的日志标识
    LogEntry* candidates = (LogEntry*)malloc(entryCount * sizeof(LogEntry));
    int candCount = 0;
    for (int i = 0; i < entryCount; i++) {
        if (entries[i].count >= 3) {
            candidates[candCount++] = entries[i];
        }
    }

    // 根据排序规则进行排序
    qsort(candidates, candCount, sizeof(LogEntry), _cmp);

    // 构建返回数组
    char** result = (char**)malloc(candCount * sizeof(char*));
    for (int i = 0; i < candCount; i++) {
        result[i] = (char*)malloc(strlen(candidates[i].name) + 1);
        strcpy(result[i], candidates[i].name);
    }

    *returnSize = candCount;
    free(entries);
    free(candidates);
    return result;
}
