var countValidPatterns = function(L) {
    // 统计每个大写字母出现次数
    const cnt = new Array(26).fill(0);
    for (let i = 0; i < L.length; i++) {
        cnt[L.charCodeAt(i) - 65]++;
    }

    const memo = new Map();

    function dfs(cnt, prev) {
        // 构建状态键用于记忆化
        const key = prev + '#' + cnt.join(',');
        if (memo.has(key)) return memo.get(key);

        // 统计剩余总字母数
        let total = 0;
        for (let i = 0; i < 26; i++) total += cnt[i];
        if (total === 0) return 1;

        let ans = 0;
        // 枚举当前可以放置的字母
        for (let i = 0; i < 26; i++) {
            if (cnt[i] > 0 && i !== prev) {
                cnt[i]--;
                ans += dfs(cnt, i);
                cnt[i]++;
            }
        }

        memo.set(key, ans);
        return ans;
    }

    // 从初始状态开始搜索
    return dfs(cnt, -1);
};
