```c
#include <string.h>
#include <stdio.h>

#define MAX_MEMO 50000

static char _memo_key[MAX_MEMO][256];
static int _memo_val[MAX_MEMO];
static int _memo_cnt = 0;

// 构建唯一的状态键
static void _build_key(int* cnt, int prev, char* key) {
    int pos = 0;
    pos += sprintf(key + pos, "%d", prev);
    for (int i = 0; i < 26; i++) {
        pos += sprintf(key + pos, ",%d", cnt[i]);
    }
}

// 检查是否已存在记忆化结果
static int _check_memo(int* cnt, int prev, int* result) {
    char key[256];
    _build_key(cnt, prev, key);
    for (int i = 0; i < _memo_cnt; i++) {
        if (strcmp(_memo_key[i], key) == 0) {
            *result = _memo_val[i];
            return 1;
        }
    }
    return 0;
}

// 记忆新状态结果
static void _add_memo(int* cnt, int prev, int val) {
    if (_memo_cnt >= MAX_MEMO) return;
    _build_key(cnt, prev, _memo_key[_memo_cnt]);
    _memo_val[_memo_cnt] = val;
    _memo_cnt++;
}

// 深度优先搜索主函数
static int _dfs(int* cnt, int prev) {
    int memo_result;
    if (_check_memo(cnt, prev, &memo_result)) return memo_result;

    int total = 0;
    for (int i = 0; i < 26; i++) total += cnt[i];
    if (total == 0) return 1;

    int ans = 0;
    for (int i = 0; i < 26; i++) {
        if (cnt[i] > 0 && i != prev) {
            cnt[i]--;
            ans += _dfs(cnt, i);
            cnt[i]++;
        }
    }

    _add_memo(cnt, prev, ans);
    return ans;
}

// 入口函数
int countValidPatterns(char* L) {
    int cnt[26] = {0};
    for (int i = 0; L[i]; i++) {
        cnt[L[i] - 'A']++;
    }
    _memo_cnt = 0;
    return _dfs(cnt, -1);
}
