```javascript
/**
 * @param {number[]} portRates - 端口每分钟流量速率数组
 * @return {number[]} - 对应分钟之后出现更大流量速率的等待分钟数
 */
var StatPortRates = function(portRates) {
    const n = portRates.length;
    const result = new Array(n).fill(0);
    const stack = []; // 单调栈，存放尚未找到更大值的下标

    for (let i = 0; i < n; i++) {
        // 当前流量速率更大，则更新之前下标的等待时间
        while (stack.length && portRates[stack[stack.length - 1]] < portRates[i]) {
            const j = stack.pop();
            result[j] = i - j;
        }
        // 当前下标入栈
        stack.push(i);
    }

    return result;
};
```

```c
#include <stdlib.h>
#include <string.h>

int* StatPortRates(int* portRates, int portRatesSize, int* returnSize) {
    *returnSize = portRatesSize;
    int* result = (int*)malloc(portRatesSize * sizeof(int));
    memset(result, 0, portRatesSize * sizeof(int));
    int* stack = (int*)malloc(portRatesSize * sizeof(int));
    int top = 0; // 栈顶指针

    for (int i = 0; i < portRatesSize; i++) {
        // 当前流量速率更大，说明找到了之前栈中下标的答案
        while (top > 0 && portRates[stack[top - 1]] < portRates[i]) {
            int j = stack[--top];
            result[j] = i - j;
        }
        // 当前下标入栈
        stack[top++] = i;
    }

    free(stack);
    return result;
}
