class Solution {
public:
    int MaxPlayers(int playerCount, vector<vector<int> >& playerTimeRange) {
        // 按结束时间排序
        sort(playerTimeRange.begin(), playerTimeRange.end(),
             [](const vector<int>& a, const vector<int>& b) {
                 return a[1] < b[1];
             });

        int ans = 0;
        int lastEnd = -1; // 上一个安排的结束时间

        for (int i = 0; i < playerCount; i++) {
            int start = playerTimeRange[i][0];
            int end = playerTimeRange[i][1];

            // 若不冲突则安排当前试玩
            if (start >= lastEnd) {
                ans++;
                lastEnd = end;
            }
        }

        return ans;
    }
};
