#include <stdlib.h>

// 比较函数，用于按结束时间排序
int _cmp(const void* a, const void* b) {
    int* ia = *(int**)a;
    int* ib = *(int**)b;
    if (ia[1] != ib[1]) return ia[1] - ib[1];
    return ia[0] - ib[0];
}

int MaxPlayers(int playerCount, int** playerTimeRange, int playerTimeRangeSize) {
    if (playerTimeRangeSize == 0) return 0;

    // 按结束时间排序
    qsort(playerTimeRange, playerTimeRangeSize, sizeof(int*), _cmp);

    int count = 1;
    int lastEnd = playerTimeRange[0][1]; // 记录上一次安排的结束时间

    for (int i = 1; i < playerTimeRangeSize; i++) {
        // 若不冲突则安排当前试玩
        if (playerTimeRange[i][0] >= lastEnd) {
            count++;
            lastEnd = playerTimeRange[i][1];
        }
    }

    return count;
}
