import java.util.*;

class Solution {
    public List<String> allBuildOrders(List<String> modules, List<List<String>> dependencies) {
        if (modules.isEmpty()) {
            return new ArrayList<>();
        }
        Map<String, Integer> indeg = new HashMap<>();
        for (String m : modules) {
            indeg.put(m, 0);
        }
        Map<String, List<String>> g = new HashMap<>();
        for (List<String> e : dependencies) {
            String a = e.get(0), b = e.get(1);
            if (!indeg.containsKey(a) || !indeg.containsKey(b)) {
                continue;
            }
            g.computeIfAbsent(b, k -> new ArrayList<>()).add(a);
            indeg.put(a, indeg.get(a) + 1);
        }

        // Kahn 判环
        Map<String, Integer> tmp = new HashMap<>(indeg);
        Deque<String> q = new ArrayDeque<>();
        for (String m : modules) {
            if (tmp.get(m) == 0) q.addLast(m);
        }
        int seen = 0;
        while (!q.isEmpty()) {
            String u = q.removeFirst();
            seen++;
            for (String v : g.getOrDefault(u, new ArrayList<>())) {
                tmp.put(v, tmp.get(v) - 1);
                if (tmp.get(v) == 0) q.addLast(v);
            }
        }
        if (seen != modules.size()) return new ArrayList<>();

        Map<String, Integer> indegMut = new HashMap<>(indeg);
        List<String> path = new ArrayList<>();
        List<String> out = new ArrayList<>();

        dfsAll(modules, g, indegMut, path, out);
        Collections.sort(out);
        return out;
    }

    private void dfsAll(List<String> modules, Map<String, List<String>> g,
                        Map<String, Integer> indegMut, List<String> path, List<String> out) {
        if (path.size() == modules.size()) {
            out.add(String.join(" ", path));
            return;
        }
        Set<String> inPath = new HashSet<>(path);
        List<String> cand = new ArrayList<>();
        for (String m : modules) {
            if (!inPath.contains(m) && indegMut.get(m) == 0) {
                cand.add(m);
            }
        }
        Collections.sort(cand);
        for (String m : cand) {
            path.add(m);
            for (String nei : g.getOrDefault(m, new ArrayList<>())) {
                indegMut.put(nei, indegMut.get(nei) - 1);
            }
            dfsAll(modules, g, indegMut, path, out);
            for (String nei : g.getOrDefault(m, new ArrayList<>())) {
                indegMut.put(nei, indegMut.get(nei) + 1);
            }
            path.remove(path.size() - 1);
        }
    }
}
