            }
        }

        // 按字典序构造答案
        string ans;
        for (int i = 0; i < 26; i++) {
            ans.append(minCnt[i], char('a' + i));
        }

        // 输出格式要求加双引号
        return "\"" + ans + "\"";
    }
};
