class Solution {
public:
    vector<int> timeClassification(string timeRange) {
        // 去除首尾引号
        if (!timeRange.empty() && timeRange[0] == '"') {
            timeRange = timeRange.substr(1);
        }
        if (!timeRange.empty() && timeRange.back() == '"') {
            timeRange.pop_back();
        }

        // 分割字符串
        int blank = timeRange.find(' ');
        string a = timeRange.substr(0, blank);
        string b = timeRange.substr(blank + 1);

        int p1 = a.find(':');
        int p2 = b.find(':');

        int start = stoi(a.substr(0, p1)) * 60 + stoi(a.substr(p1 + 1));
        int end = stoi(b.substr(0, p2)) * 60 + stoi(b.substr(p2 + 1));

        vector<int> ans(3, 0);
        int secondCnt = 0;

        for (int i = start; i < end; i++) {
            // 第一档优先
            if ((i >= 12 * 60 && i < 13 * 60 + 30) ||
                (i >= 17 * 60 + 30 && i < 18 * 60)) {
                ans[0]++;
            } else if (secondCnt < 600) {
                // 非第一档前 600 分钟属第二档
                ans[1]++;
                secondCnt++;
            } else {
                // 其他归第三档
                ans[2]++;
            }
        }

        return ans;
    }
};
