using namespace std;

class Solution {
public:
    string getClassMonitor(vector<string>& names, vector<string>& ballotTickets) {
        int n = (int)names.size();

        // 原始总票数超过 3N，直接无效
        if ((int)ballotTickets.size() > 3 * n) {
            return "Invalid election.";
        }

        // 特殊标记：表示该写法有歧义
        const string special = "#INVALID#";
        unordered_map<string, string> mapping;

        // 预处理每个名字的所有合法连续段写法
        for (string& name : names) {
            vector<string> parts = split(name, '-');
            int m = (int)parts.size();

            for (int i = 0; i < m; i++) {
                string cur = "";
                for (int j = i; j < m; j++) {
                    if (j > i) cur += "-";
                    cur += parts[j];

                    if (!mapping.count(cur)) mapping[cur] = name;
                    else if (mapping[cur] != name) mapping[cur] = special;
                }
            }
        }

        // 统计有效票
        unordered_map<string, int> cnt;
        int validVotes = 0;

        for (string& ticket : ballotTickets) {
            if (mapping.count(ticket) && mapping[ticket] != special) {
                string person = mapping[ticket];
                cnt[person]++;
                validVotes++;
            }
        }

        if (validVotes == 0) return "Invalid election.";

        for (auto& p : cnt)
            if (p.second > n) return "Invalid election.";

        // 找出票数最多且字典序最小者
        string ans = "";
        int maxVote = -1;
        for (auto& p : cnt) {
            if (p.second > maxVote || (p.second == maxVote && p.first < ans)) {
                maxVote = p.second;
                ans = p.first;
            }
        }
        return ans;
    }

private:
    // 按分隔符拆分字符串
    vector<string> split(const string& s, char delim) {
        vector<string> res;
        string cur;
        for (char c : s) {
            if (c == delim) {
                res.push_back(cur);
                cur.clear();
            } else cur += c;
        }
        res.push_back(cur);
        return res;
    }
};
