        if (match && match !== '#INVALID#') {
            votes.set(match, (votes.get(match) || 0) + 1);
            validVotes++;
        }
    }

    if (validVotes === 0) return "Invalid election.";
    for (const v of votes.values()) if (v > N) return "Invalid election.";

    let best = null, maxVotes = -1;
    for (const [name, cnt] of votes) {
        if (cnt > maxVotes || (cnt === maxVotes && name < best)) {
            maxVotes = cnt;
            best = name;
        }
    }
    return best;
