#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    string sort(string sortResolutions) {
        // 去掉首尾空白字符
        while (!sortResolutions.empty() && isspace((unsigned char)sortResolutions.back())) {
            sortResolutions.pop_back();
        }
        int start = 0;
        while (start < (int)sortResolutions.size() && isspace((unsigned char)sortResolutions[start])) {
            start++;
        }
        sortResolutions = sortResolutions.substr(start);

        // 若输入为空则直接返回空串
        if (sortResolutions.empty()) {
            return "";
        }

        // 用输入流按空格切分分辨率字符串
        stringstream ss(sortResolutions);
        vector<tuple<string, int, long long, int>> arr;
        string s;

        while (ss >> s) {
            // 按 'x' 分割宽高
            int pos = s.find('x');
            int w = stoi(s.substr(0, pos));
            int h = stoi(s.substr(pos + 1));

            // 判断清晰度等级
            int level;
            if (w >= 3840 && h >= 2160) level = 3;
            else if (w >= 2560 && h >= 1440) level = 2;
            else if (w >= 1920 && h >= 1080) level = 1;
            else level = 0;

            // 保存排序信息
            arr.push_back({s, level, 1LL * w * h, w});
        }

        // 按题意排序
        sort(arr.begin(), arr.end(), [](auto& a, auto& b) {
            if (get<1>(a) != get<1>(b)) return get<1>(a) > get<1>(b);
            if (get<2>(a) != get<2>(b)) return get<2>(a) > get<2>(b);
            if (get<3>(a) != get<3>(b)) return get<3>(a) > get<3>(b);
            return false;
        });

        // 拼接结果字符串
        string ans;
        ans.push_back('"');
        for (int i = 0; i < arr.size(); i++) {
            if (i > 0) ans += ' ';
            ans += get<0>(arr[i]);
        }
        ans.push_back('"');
        return ans;
    }
};
