```javascript
var sort = function(sortResolutions) {
    // 计算清晰度等级函数
    const getLevel = (w, h) => {
        if (w >= 3840 && h >= 2160) return 3;
        if (w >= 2560 && h >= 1440) return 2;
        if (w >= 1920 && h >= 1080) return 1;
        return 0;
    };

    // 去除首尾空白并分割分辨率字符串
    const items = sortResolutions.trim().split(/\s+/).filter(s => s.length > 0).map(s => {
        const [wStr, hStr] = s.split('x');
        const w = parseInt(wStr), h = parseInt(hStr);
        return { name: s, level: getLevel(w, h), area: w * h, width: w };
    });

    // 按题意排序
    items.sort((a, b) => {
        if (a.level !== b.level) return b.level - a.level;
        if (a.area !== b.area) return b.area - a.area;
        return b.width - a.width;
    });

    // 返回拼接结果
    return '"' + items.map(x => x.name).join(' ') + '"';
};
