```javascript
var networkPlanning = function(roomArrangement) {
    var m = roomArrangement.length;
    if (m === 0) return 0;
    var n = roomArrangement[0].length;
    if (n === 0) return 0;

    // 给空地编号
    var emptyId = {};
    var emptyCells = [];
    for (var i = 0; i < m; i++) {
        for (var j = 0; j < n; j++) {
            if (roomArrangement[i][j] === '.') {
                emptyId[i * n + j] = emptyCells.length;
                emptyCells.push([i, j]);
            }
        }
    }

    var totalEmpty = emptyCells.length;
    if (totalEmpty === 0) return 0;

    // 生成所有候选 AP
    var candidates = [];
    var coversOfEmpty = [];
    for (var i = 0; i < totalEmpty; i++) coversOfEmpty.push([]);

    for (var r = 0; r < m; r++) {
        for (var c = 0; c < n; c++) {
            if (roomArrangement[r][c] !== '.') continue;

            var fullMask = 0n;
            var emptyMask = 0n;
            var emptyList = [];

            for (var dr = -1; dr <= 1; dr++) {
                var nr = r + dr;
                if (nr < 0 || nr >= m) continue;
                for (var dc = -1; dc <= 1; dc++) {
                    var nc = c + dc;
                    if (nc < 0 || nc >= n) continue;
                    var idx = nr * n + nc;
                    fullMask |= (1n << BigInt(idx));
                    if (roomArrangement[nr][nc] === '.') {
                        var eid = emptyId[idx];
                        emptyMask |= (1n << BigInt(eid));
                        emptyList.push(eid);
                    }
                }
            }

            var cid = candidates.length;
            candidates.push([fullMask, emptyMask, emptyList]);

            for (var k = 0; k < emptyList.length; k++) {
                coversOfEmpty[emptyList[k]].push(cid);
            }
        }
    }

    // 检查无覆盖的空地
    for (var eid = 0; eid < totalEmpty; eid++) {
        if (coversOfEmpty[eid].length === 0) return -1;
    }

    var allCovered = (1n << BigInt(totalEmpty)) - 1n;
    var best = totalEmpty + 1;

    function dfs(covered, occupied, used) {
        if (used >= best) return;
        if (covered === allCovered) {
            best = used;
            return;
        }

        var targetList = [];
        var minChoices = totalEmpty + 1;

        for (var eid = 0; eid < totalEmpty; eid++) {
            if (covered & (1n << BigInt(eid))) continue;

            var valid = [];
            var list = coversOfEmpty[eid];
            for (var k = 0; k < list.length; k++) {
                var cid = list[k];
                if (!(candidates[cid][0] & occupied)) {
                    valid.push(cid);
                }
            }

            if (valid.length === 0) return;
            if (valid.length < minChoices) {
                minChoices = valid.length;
                targetList = valid;
                if (minChoices === 1) break;
            }
        }

        for (var k = 0; k < targetList.length; k++) {
            var cid = targetList[k];
            var cand = candidates[cid];
            dfs(covered | cand[1], occupied | cand[0], used + 1);
            if (best === 1) return;
        }
    }

    dfs(0n, 0n, 0);
    return best > totalEmpty ? -1 : best;
};
