from typing import List
from collections import Counter

class Solution:
    def countKeys(self, s: str) -> List[List[int]]:
        # 统计每个按键被按下的次数
        cnt = Counter()
        i = 0
        n = len(s)

        while i < n:
            # 优先匹配失灵按键对应的转义串
            if i + 1 < n and s[i] == 'u' and s[i + 1] == 'u':
                cnt['j'] += 1
                i += 2
            elif i + 1 < n and s[i] == 't' and s[i + 1] == 't':
                cnt['b'] += 1
                i += 2
            else:
                # 否则就是正常按键
                cnt[s[i]] += 1
                i += 1

        # 字符转义函数
        def encode(c: str) -> int:
            if '0' <= c <= '9':
                return ord(c) - ord('0')
            return ord(c) - ord('a') + 10

        # 按次数降序，字符升序排序
        keys = sorted(cnt.items(), key=lambda x: (-x[1], x[0]))

        # 生成结果
        ans = []
        for c, num in keys:
            ans.append([encode(c), num])

        return ans
