class Solution:
    def mergeLogs(self, paths, responseTimes):
        # 获取日志总数
        n = len(paths)

        # 用于存储最终答案
        ans = []

        # i 表示当前正在处理的分组起点
        i = 0

        # 线性扫描整个数组
        while i < n:
            # 当前组的起始下标
            start = i

            # 当前组的请求路径
            current_path = paths[i]

            # 当前组内元素个数
            count = 0

            # 当前组内响应时间总和
            total = 0

            # 向后扩展当前组，直到路径发生变化
            while i < n and paths[i] == current_path:
                count += 1
                total += responseTimes[i]
                i += 1

            # 计算当前组平均响应时间，题目要求向下取整
            avg = total // count

            # 将当前组统计结果加入答案
            ans.append([start, count, avg])

        # 返回所有分组结果
        return ans
