int** mergeLogs(char** paths, int pathsSize, int* responseTimes, int responseTimesSize, int* returnSize) {
    if (pathsSize == 0) {
        *returnSize = 0;
        return NULL;
    }

    int** result = (int**)malloc(pathsSize * sizeof(int*));
    int groupCount = 0;
    int i = 0;

    while (i < pathsSize) {
        int start = i;
        char* currentPath = paths[i];
        int count = 0;
        int total = 0;

        while (i < pathsSize && strcmp(paths[i], currentPath) == 0) {
            count++;
            total += responseTimes[i];
            i++;
        }

        int avg = total / count;
        result[groupCount] = (int*)malloc(3 * sizeof(int));
        result[groupCount][0] = start;
        result[groupCount][1] = count;
        result[groupCount][2] = avg;
        groupCount++;
    }

    *returnSize = groupCount;
    return result;
}
