            deque<int>& other = (turn == 0) ? b : a;

            // 回合开始时无牌可出，游戏结束
            if (cur.empty()) {
                if (!other.empty()) {
                    return other.front();
                }
                return table.empty() ? 0 : table.back();
            }

            // 出牌
            int x = cur.front();
            cur.pop_front();
            moves++;

            // 记录出牌前桌面是否非空，供 J 特效判断
            bool hadTable = !table.empty();

            int oldSame = pos[x].empty() ? -1 : pos[x].back();

            // 放到桌面顶端
            table.push_back(x);
            pos[x].push_back((int)table.size() - 1);

            bool captured = false;
            int start = -1;

            // J 特效优先
            if (x == 11 && hadTable) {
                start = 0;
                captured = true;
            } else if (oldSame != -1) {
                // 普通同点数匹配
                start = oldSame;
                captured = true;
            }

            if (captured) {
                // 保存收走的牌，顺序保持为桌面从下到上
                vector<int> gained(table.begin() + start, table.end());

                // 从后往前同步弹出位置栈
                for (int i = (int)table.size() - 1; i >= start; i--) {
                    int v = table[i];
                    pos[v].pop_back();
                }

                // 删除桌面后缀
                table.resize(start);

                // 收到当前玩家牌堆底部
                for (int v : gained) {
                    cur.push_back(v);
                }
                // 收牌后当前玩家继续出牌
            } else {
                // 没收牌则换对手
                turn ^= 1;
            }

            // 超过 10000 次仍未结束，判平局
