## 解题思路

这题本质上是 **字符串解析 + 哈希表模拟**。

我们需要按顺序解析批量命令，每条命令独立执行；即使某条失败，也不能影响后续命令继续处理。
因此最适合用：

* **字符串分割**：把整体字符串拆成一条条命令
* **哈希表**：维护当前系统中的 `rule_id -> rule_index`

### 核心规则整理

对于每条命令：

1. **命令关键字必须合法**

   * 只能是 `add_rule`、`mod_rule`、`del_rule`

2. **属性必须合法**

   * `rule_id`、`rule_index` 的值都必须是数字，且范围在 `1 ~ 9999`
   * 缺少必要属性也算失败

3. **各操作的业务规则**

   * `add_rule`：

     * 必须有 `rule_id` 和 `rule_index`
     * 当前 `rule_id` 不存在才能添加成功
   * `mod_rule`：

     * 必须有 `rule_id` 和 `rule_index`
     * 当前 `rule_id` 必须存在
     * 新旧 `rule_index` 必须不同
   * `del_rule`：

     * 必须有 `rule_id`
     * 当前 `rule_id` 必须存在


### 实现方法

用一个哈希表记录当前规则：

* 键：`rule_id`
* 值：`rule_index`

然后遍历每条命令：

1. 先拆出操作关键字和各属性
2. 校验关键字、属性格式、数值范围
3. 按操作类型模拟执行
4. 若失败则失败次数加一

### 复杂度分析

设总字符串长度为 `n`，命令条数为 `m`。

* **时间复杂度：`O(n)`**

  * 每个字符最多被扫描、分割、解析一次
  * 哈希表增删改查均摊 `O(1)`
* **空间复杂度：`O(m)`**

  * 最多存下所有成功添加的规则

这个复杂度对于题目中“不超过 1000 条命令”的数据范围完全足够。

## 代码实现

#code-switcher
```python
class Solution:
    def getErrorCount(self, rules: str) -> int:
        # 判断字符串是否是 1~9999 的合法数字
        def valid_num(s: str) -> bool:
            if not s or not s.isdigit():
                return False
            x = int(s)
            return 1 <= x <= 9999

        # 空串直接返回 0
        if not rules:
            return 0

        # 去掉整体首尾可能存在的双引号
        if len(rules) >= 2 and rules[0] == '"' and rules[-1] == '"':
            rules = rules[1:-1]

        # 按每条命令切分
        cmds = rules.split("][")

        # 哈希表：rule_id -> rule_index
        mp = {}
        ans = 0

        for cmd in cmds:
            # 去掉每条命令首尾可能残留的方括号
            cmd = cmd.strip("[]")
            parts = cmd.split()

            # 至少要有操作关键字
            if not parts:
                ans += 1
                continue

            op = parts[0]
            attrs = {}

            ok = True

            # 解析属性
            for i in range(1, len(parts)):
                if '=' not in parts[i]:
                    ok = False
                    break
                key, val = parts[i].split('=', 1)
                if key not in ("rule_id", "rule_index"):
                    ok = False
                    break
                if not valid_num(val):
                    ok = False
                    break
                attrs[key] = int(val)

            if not ok:
                ans += 1
                continue

            # 分类处理
            if op == "add_rule":
                # add 必须同时有 rule_id 和 rule_index
                if "rule_id" not in attrs or "rule_index" not in attrs:
                    ans += 1
                    continue
                rule_id = attrs["rule_id"]
                rule_index = attrs["rule_index"]
                if rule_id in mp:
                    ans += 1
                else:
                    mp[rule_id] = rule_index

            elif op == "mod_rule":
                # mod 必须同时有 rule_id 和 rule_index
                if "rule_id" not in attrs or "rule_index" not in attrs:
                    ans += 1
                    continue
                rule_id = attrs["rule_id"]
                rule_index = attrs["rule_index"]
                if rule_id not in mp or mp[rule_id] == rule_index:
                    ans += 1
                else:
                    mp[rule_id] = rule_index

            elif op == "del_rule":
                # del 只要求有 rule_id
                if "rule_id" not in attrs:
                    ans += 1
                    continue
                rule_id = attrs["rule_id"]
                if rule_id not in mp:
                    ans += 1
                else:
                    del mp[rule_id]

            else:
                # 非法操作关键字
                ans += 1

        return ans
```

```java
import java.util.*;

class Solution {
    public int getErrorCount(String rules) {
        // 空串直接返回 0
        if (rules == null || rules.length() == 0) {
            return 0;
        }

        // 去掉整体首尾可能存在的双引号
        if (rules.length() >= 2 && rules.charAt(0) == '"' && rules.charAt(rules.length() - 1) == '"') {
            rules = rules.substring(1, rules.length() - 1);
        }

        // 按每条命令切分
        String[] cmds = rules.split("\\]\\[");

        // 哈希表：rule_id -> rule_index
        Map<Integer, Integer> map = new HashMap<>();
        int ans = 0;

        for (String cmd : cmds) {
            // 去掉每条命令首尾可能残留的方括号
            cmd = trimBrackets(cmd);
            if (cmd.length() == 0) {
                ans++;
                continue;
            }

            String[] parts = cmd.split(" ");
            if (parts.length == 0) {
                ans++;
                continue;
            }

            String op = parts[0];
            Map<String, Integer> attrs = new HashMap<>();
            boolean ok = true;

            // 解析属性
            for (int i = 1; i < parts.length; i++) {
                int idx = parts[i].indexOf('=');
                if (idx == -1) {
                    ok = false;
                    break;
                }

                String key = parts[i].substring(0, idx);
                String val = parts[i].substring(idx + 1);

                if (!key.equals("rule_id") && !key.equals("rule_index")) {
                    ok = false;
                    break;
                }

                if (!validNum(val)) {
                    ok = false;
                    break;
                }

                attrs.put(key, Integer.parseInt(val));
            }

            if (!ok) {
                ans++;
                continue;
            }

            // 分类处理
            if (op.equals("add_rule")) {
                // add 必须同时有 rule_id 和 rule_index
                if (!attrs.containsKey("rule_id") || !attrs.containsKey("rule_index")) {
                    ans++;
                    continue;
                }

                int ruleId = attrs.get("rule_id");
                int ruleIndex = attrs.get("rule_index");

                if (map.containsKey(ruleId)) {
                    ans++;
                } else {
                    map.put(ruleId, ruleIndex);
                }

            } else if (op.equals("mod_rule")) {
                // mod 必须同时有 rule_id 和 rule_index
                if (!attrs.containsKey("rule_id") || !attrs.containsKey("rule_index")) {
                    ans++;
                    continue;
                }

                int ruleId = attrs.get("rule_id");
                int ruleIndex = attrs.get("rule_index");

                if (!map.containsKey(ruleId) || map.get(ruleId) == ruleIndex) {
                    ans++;
                } else {
                    map.put(ruleId, ruleIndex);
                }

            } else if (op.equals("del_rule")) {
                // del 只要求有 rule_id
                if (!attrs.containsKey("rule_id")) {
                    ans++;
                    continue;
                }

                int ruleId = attrs.get("rule_id");

                if (!map.containsKey(ruleId)) {
                    ans++;
                } else {
                    map.remove(ruleId);
                }

            } else {
                // 非法操作关键字
                ans++;
            }
        }

        return ans;
    }

    // 判断字符串是否是 1~9999 的合法数字
    private boolean validNum(String s) {
        if (s == null || s.length() == 0) {
            return false;
        }

        for (int i = 0; i < s.length(); i++) {
            if (!Character.isDigit(s.charAt(i))) {
                return false;
            }
        }

        int x = Integer.parseInt(s);
        return x >= 1 && x <= 9999;
    }

    // 去掉字符串首尾的 '[' 和 ']'
    private String trimBrackets(String s) {
        int l = 0, r = s.length() - 1;
        while (l <= r && s.charAt(l) == '[') {
            l++;
        }
        while (l <= r && s.charAt(r) == ']') {
            r--;
        }
        return s.substring(l, r + 1);
    }
}
