                    mp[rule_id] = rule_index;
                }

            } else if (op == "del_rule") {
                // del 只要求有 rule_id
                if (!attrs.count("rule_id")) {
                    ans++;
                    continue;
                }

                int rule_id = attrs["rule_id"];

                if (!mp.count(rule_id)) {
                    ans++;
                } else {
                    mp.erase(rule_id);
                }

            } else {
                // 非法操作关键字
                ans++;
            }
        }

        return ans;
    }

private:
    // 判断字符串是否是 1~9999 的合法数字
    bool validNum(const string& s) {
        if (s.empty()) {
            return false;
        }
        for (char c : s) {
            if (c < '0' || c > '9') {
                return false;
            }
        }
        int x = stoi(s);
        return x >= 1 && x <= 9999;
    }

    // 去掉字符串首尾的 '[' 和 ']'
    string trimBrackets(const string& s) {
        int l = 0, r = (int)s.size() - 1;
        while (l <= r && s[l] == '[') l++;
        while (l <= r && s[r] == ']') r--;
        if (l > r) return "";
        return s.substr(l, r - l + 1);
    }

    // 按 "][" 切分命令
    vector<string> splitCommands(const string& s) {
        vector<string> res;
        int start = 0;
        for (int i = 0; i + 1 < (int)s.size(); i++) {
            if (s[i] == ']' && s[i + 1] == '[') {
                res.push_back(s.substr(start, i - start + 1));
                start = i + 1;
            }
        }
        res.push_back(s.substr(start));
        return res;
    }

    // 按空格切分
    vector<string> splitBySpace(const string& s) {
        vector<string> res;
        string cur;
        for (char c : s) {
            if (c == ' ') {
                if (!cur.empty()) {
                    res.push_back(cur);
                    cur.clear();
                }
            } else {
                cur.push_back(c);
            }
        }
        if (!cur.empty()) {
            res.push_back(cur);
        }
        return res;
    }
};
