var getErrorCount = function(rules) {
    // 判断字符串是否为 1~9999 的合法数字
    function validNum(s) {
        if (!s || s.length === 0) return false;
        for (let i = 0; i < s.length; i++) {
            if (s[i] < '0' || s[i] > '9') return false;
        }
        const x = parseInt(s, 10);
        return x >= 1 && x <= 9999;
    }

    // 空串直接返回 0
    if (!rules || rules.length === 0) return 0;

    // 去掉整体首尾可能存在的双引号
    if (rules.length >= 2 && rules[0] === '"' && rules[rules.length - 1] === '"') {
        rules = rules.slice(1, -1);
    }
    if (rules.length === 0) return 0;

    // 按 "][" 切分命令
    const cmds = rules.split('][');

    // 哈希表：rule_id -> rule_index
    const mp = new Map();
    let ans = 0;

    for (let rawCmd of cmds) {
        // 去掉首尾可能残留的方括号
        let cmd = rawCmd.trim();
        if (cmd.length > 0 && cmd[0] === '[') cmd = cmd.slice(1);
        if (cmd.length > 0 && cmd[cmd.length - 1] === ']') cmd = cmd.slice(0, -1);

        const parts = cmd.split(' ');
        if (parts.length === 0 || parts[0] === '') {
            ans++;
            continue;
        }

        const op = parts[0];
        const attrs = {};
        let ok = true;

        // 解析属性
        for (let i = 1; i < parts.length; i++) {
            const eqIdx = parts[i].indexOf('=');
            if (eqIdx === -1) { ok = false; break; }
            const key = parts[i].substring(0, eqIdx);
            const val = parts[i].substring(eqIdx + 1);

            if (key !== 'rule_id' && key !== 'rule_index') { ok = false; break; }
            if (!validNum(val)) { ok = false; break; }
            attrs[key] = parseInt(val, 10);
        }

        if (!ok) { ans++; continue; }

        // 分类处理
        if (op === 'add_rule') {
            if (!('rule_id' in attrs) || !('rule_index' in attrs)) { ans++; continue; }
            const ruleId = attrs['rule_id'];
            const ruleIndex = attrs['rule_index'];
            if (mp.has(ruleId)) { ans++; continue; }
            mp.set(ruleId, ruleIndex);
        } else if (op === 'mod_rule') {
            if (!('rule_id' in attrs) || !('rule_index' in attrs)) { ans++; continue; }
            const ruleId = attrs['rule_id'];
            const ruleIndex = attrs['rule_index'];
            if (!mp.has(ruleId) || mp.get(ruleId) === ruleIndex) { ans++; continue; }
            mp.set(ruleId, ruleIndex);
        } else if (op === 'del_rule') {
            if (!('rule_id' in attrs)) { ans++; continue; }
            const ruleId = attrs['rule_id'];
            if (!mp.has(ruleId)) { ans++; continue; }
            mp.delete(ruleId);
        } else {
            // 非法操作关键字
            ans++;
        }
    }

    return ans;
};
