#include <string.h>
#include <stdlib.h>
#include <ctype.h>

/**
 * @param rules 批量操作字符串，格式 "[cmd][cmd]..."
 * @return 配置失败的次数
 */
int getErrorCount(char* rules) {
    int len = strlen(rules);
    if (len == 0) return 0;

    // 去掉首尾可能存在的双引号
    int start = 0, end = len - 1;
    if (len >= 2 && rules[0] == '"' && rules[end] == '"') {
        start = 1;
        end = len - 2;
    }
    if (start > end) return 0;

    // 用静态数组存储 rule_id -> rule_index 映射（id 范围 1~9999）
    static int hasEntry[10000];
    static int mp[10000];

    // 重置全局状态（支持多次调用）
    memset(hasEntry, 0, sizeof(hasEntry));

    int errors = 0;
    int i = start;
    while (i <= end) {
        // 找到命令开始 '['
        while (i <= end && rules[i] != '[') i++;
        if (i > end) break;
        i++; // 跳过 '['

        // 找到命令结束 ']'
        int cmdStart = i;
        int depth = 0;
        while (i <= end) {
            if (rules[i] == '[') depth++;
            else if (rules[i] == ']') {
                if (depth == 0) break;
                depth--;
            }
            i++;
        }
        int cmdEnd = i - 1;
        if (i > end) break;
        i++; // 跳过 ']'

        // 解析命令内容：按空格分割 token
        int pos = cmdStart;
        int has_id = 0, has_index = 0;
        int rule_id = 0, rule_index = 0;
        int attrOk = 1;
        char op[20] = "";
        int opSet = 0;

        while (pos <= cmdEnd) {
            // 跳过空格
            while (pos <= cmdEnd && rules[pos] == ' ') pos++;
            if (pos > cmdEnd) break;

            // 读取一个 token
            int tokStart = pos;
            while (pos <= cmdEnd && rules[pos] != ' ' && rules[pos] != '=') pos++;

            if (!opSet) {
                // 第一个 token 是操作关键字
                int tokLen = pos - tokStart;
                if (tokLen >= 20) { attrOk = 0; break; }
                memcpy(op, rules + tokStart, tokLen);
                op[tokLen] = '\0';
                opSet = 1;
                if (pos > cmdEnd || rules[pos] != ' ') { attrOk = 0; break; }
                continue;
            }

            // 后续 token 是 key=value
            int keyLen = pos - tokStart;
            if (pos > cmdEnd || rules[pos] != '=') { attrOk = 0; break; }
            pos++; // 跳过 '='

            // 读取 value
            int valStart = pos;
            while (pos <= cmdEnd && rules[pos] != ' ') pos++;
            int valLen = pos - valStart;
            if (valLen == 0) { attrOk = 0; break; }

            // 校验 value 为 1~9999 的数字
            int v = 0;
            for (int k = 0; k < valLen; k++) {
                if (rules[valStart + k] < '0' || rules[valStart + k] > '9') {
                    attrOk = 0;
                    break;
                }
                v = v * 10 + (rules[valStart + k] - '0');
            }
            if (!attrOk || v < 1 || v > 9999) { attrOk = 0; break; }

            // 校验 key
            if (keyLen == 7 && memcmp(rules + tokStart, "rule_id", 7) == 0) {
                has_id = 1; rule_id = v;
            } else if (keyLen == 10 && memcmp(rules + tokStart, "rule_index", 10) == 0) {
                has_index = 1; rule_index = v;
            } else {
                attrOk = 0; break;
            }
        }

        if (!attrOk || !opSet) { errors++; continue; }

        // 分类处理
        if (strcmp(op, "add_rule") == 0) {
            if (!has_id || !has_index) { errors++; continue; }
            if (hasEntry[rule_id]) { errors++; continue; }
            hasEntry[rule_id] = 1;
            mp[rule_id] = rule_index;
        } else if (strcmp(op, "mod_rule") == 0) {
            if (!has_id || !has_index) { errors++; continue; }
            if (!hasEntry[rule_id] || mp[rule_id] == rule_index) { errors++; continue; }
            mp[rule_id] = rule_index;
        } else if (strcmp(op, "del_rule") == 0) {
            if (!has_id) { errors++; continue; }
            if (!hasEntry[rule_id]) { errors++; continue; }
            hasEntry[rule_id] = 0;
        } else {
            errors++;
        }
    }

    return errors;
}
