/**
 * @param {number} n - 敌军阵营的边长
 * @param {number[][]} guards - 哨兵位置列表 [x, y]
 * @return {number[]} - 返回 [最短路径条数, 最短路径长度]
 */
var countShortestPaths = function(n, guards) {
    // 起点：底行正中 (0, n/2)；终点：顶行正中 (n-1, n/2)
    const sy = n >> 1;
    const sx = 0, ex = n - 1, ey = sy;

    // 标记每个哨兵的 3×3 九宫格（切比雪夫距离 ≤ 1）为禁区
    const ban = Array.from({ length: n }, () => new Array(n).fill(false));
    for (const g of guards) {
        const gx = g[0], gy = g[1];
        for (let dx = -1; dx <= 1; dx++) {
            for (let dy = -1; dy <= 1; dy++) {
                const nx = gx + dx, ny = gy + dy;
                if (nx >= 0 && nx < n && ny >= 0 && ny < n) {
                    ban[nx][ny] = true;
                }
            }
        }
    }

    // 起点或终点在禁区内则不可达
    if (ban[sx][sy] || ban[ex][ey]) return [0, 0];

    // BFS：dist 存最短边数（-1 表示未访问），ways 存方案数
    const dist = Array.from({ length: n }, () => new Array(n).fill(-1));
    const ways = Array.from({ length: n }, () => new Array(n).fill(0));
    const dirs = [[1, 0], [-1, 0], [0, 1], [0, -1]];

    dist[sx][sy] = 0;
    ways[sx][sy] = 1;
    const q = [[sx, sy]];

    for (let qi = 0; qi < q.length; qi++) {
        const [x, y] = q[qi];
        for (const [dx, dy] of dirs) {
            const nx = x + dx, ny = y + dy;
            if (nx < 0 || nx >= n || ny < 0 || ny >= n || ban[nx][ny]) continue;
            const nd = dist[x][y] + 1;
            if (dist[nx][ny] === -1) {
                // 首次到达：最短路长度确定，方案数继承自前驱
                dist[nx][ny] = nd;
                ways[nx][ny] = ways[x][y];
                q.push([nx, ny]);
            } else if (dist[nx][ny] === nd) {
                // 同一最短路层上另有前驱，累加方案数
                ways[nx][ny] += ways[x][y];
            }
        }
    }

    // 可达时返回 [条数, 顶点数（边数 + 1）]
    if (dist[ex][ey] === -1) return [0, 0];
    return [ways[ex][ey], dist[ex][ey] + 1];
};
