#include <string>
#include <unordered_map>
#include <vector>
using namespace std;

class Solution {
public:
    vector<string> findMaxOccupiedPaths(string target, vector<string>& files, vector<int>& sizes) {
        // 核心：判断 target 是否作为某条文件路径本身或「target/」严格前缀出现
        bool exists = false;
        for (const string& p : files) {
            if (p == target
                || (p.size() > target.size() && p.compare(0, target.size(), target) == 0
                    && p[target.size()] == '/')) {
                exists = true;
                break;
            }
        }
        if (!exists) {
            return {};
        }
        // 核心：一级子项聚合；int64_t 存和，避免多文件大 size 相加溢出 int
        unordered_map<string, int64_t> agg;
        for (size_t i = 0; i < files.size(); ++i) {
            const string& p = files[i];
            if (p == target) {
                continue;
            }
            // 关键：compare 前缀后必须检查 target 长度处是否为 '/'，区分 /dir 与 /dir1
            if (p.size() <= target.size() || p.compare(0, target.size(), target) != 0
                || p[target.size()] != '/') {
                continue;
            }
            string rel = p.substr(target.size() + 1);
            size_t slash = rel.find('/');
            string child;
            if (slash == string::npos) {
                child = p;
            } else {
                child = target + "/" + rel.substr(0, slash);
            }
            agg[child] += static_cast<int64_t>(sizes[i]);
        }
        if (agg.empty()) {
            return {};
        }
        // 关键：最大占用及所有取到最大的路径
        int64_t mx = 0;
        for (const auto& kv : agg) {
            mx = max(mx, kv.second);
        }
        vector<string> ans;
        for (const auto& kv : agg) {
            if (kv.second == mx) {
                ans.push_back(kv.first);
            }
        }
        sort(ans.begin(), ans.end());  // 题意：并列时字典序升序
        return ans;
    }
};
