```c
#include <string.h>
#include <stdlib.h>

// 哈希表条目
typedef struct {
    char* key;
    long long val;
} Entry;

// 简单开地址哈希表
typedef struct {
    Entry* entries;
    int size;
    int cap;
} HashMap;

static unsigned long hash_str(const char* s) {
    unsigned long h = 5381;
    while (*s) h = ((h << 5) + h) + (unsigned char)(*s++);
    return h;
}

static void hm_init(HashMap* hm, int cap) {
    hm->cap = cap;
    hm->size = 0;
    hm->entries = (Entry*)calloc((size_t)cap, sizeof(Entry));
}

static void hm_ensure(HashMap* hm) {
    if (hm->size * 2 < hm->cap) return;
    int newCap = hm->cap * 2;
    Entry* old = hm->entries;
    int oldCap = hm->cap;
    hm->cap = newCap;
    hm->entries = (Entry*)calloc((size_t)newCap, sizeof(Entry));
    hm->size = 0;
    for (int i = 0; i < oldCap; i++) {
        if (old[i].key) {
            unsigned long h = hash_str(old[i].key) % (unsigned long)newCap;
            while (hm->entries[h].key)
                h = (h + 1) % (unsigned long)newCap;
            hm->entries[h] = old[i];
            hm->size++;
        }
    }
    free(old);
}

static void hm_put(HashMap* hm, const char* key, long long val) {
    hm_ensure(hm);
    unsigned long h = hash_str(key) % (unsigned long)hm->cap;
    while (hm->entries[h].key && strcmp(hm->entries[h].key, key) != 0)
        h = (h + 1) % (unsigned long)hm->cap;
    if (hm->entries[h].key) {
        hm->entries[h].val += val;
    } else {
        size_t klen = strlen(key);
        hm->entries[h].key = (char*)malloc(klen + 1);
        if (hm->entries[h].key) {
            memcpy(hm->entries[h].key, key, klen + 1);
        }
        hm->entries[h].val = val;
        hm->size++;
    }
}

static int cmp_str(const void* a, const void* b) {
    return strcmp(*(const char**)a, *(const char**)b);
}

char** findMaxOccupiedPaths(const char* target,
                            char** files, int filesSize,
                            int* sizes, int sizesSize,
                            int* resultCount) {
    // 判断 target 是否在文件系统中存在
    int exists = 0;
    size_t tlen = strlen(target);
    for (int i = 0; i < filesSize && !exists; i++) {
        size_t plen = strlen(files[i]);
        if (strcmp(files[i], target) == 0) {
            exists = 1;
        } else if (plen > tlen &&
                   strncmp(files[i], target, tlen) == 0 &&
                   files[i][tlen] == '/') {
            exists = 1;
        }
    }
    if (!exists) {
        *resultCount = 0;
        return NULL;
    }

    HashMap agg;
    hm_init(&agg, 64);

    char child_buf[2048];

    for (int i = 0; i < filesSize; i++) {
        const char* p = files[i];
        size_t plen = strlen(p);

        // 跳过 target 本身
        if (strcmp(p, target) == 0) continue;

        // 必须以 target+'/' 为前缀
        if (plen <= tlen || strncmp(p, target, tlen) != 0 || p[tlen] != '/')
            continue;

        const char* rel = p + tlen + 1;
        const char* slash = strchr(rel, '/');

        if (!slash) {
            // 直接挂在 target 下的一级文件
            hm_put(&agg, p, sizes[i]);
        } else {
            // 一级子目录：target + "/" + 第一段路径名
            size_t seg = (size_t)(slash - rel);
            int pos = 0;
            memcpy(child_buf + pos, target, tlen);
            pos += (int)tlen;
            child_buf[pos++] = '/';
            memcpy(child_buf + pos, rel, seg);
            pos += (int)seg;
            child_buf[pos] = '\0';
            hm_put(&agg, child_buf, sizes[i]);
        }
    }

    if (agg.size == 0) {
        free(agg.entries);
        *resultCount = 0;
        return NULL;
    }

    // 找最大占用
    long long mx = 0;
    for (int i = 0; i < agg.cap; i++) {
        if (agg.entries[i].key && agg.entries[i].val > mx)
            mx = agg.entries[i].val;
    }

    // 收集所有达到最大的路径
    int ans_cap = 8, cnt = 0;
    char** ans = (char**)malloc((size_t)ans_cap * sizeof(char*));
    for (int i = 0; i < agg.cap; i++) {
        if (agg.entries[i].key && agg.entries[i].val == mx) {
            if (cnt >= ans_cap) {
                ans_cap *= 2;
                ans = (char**)realloc(ans, (size_t)ans_cap * sizeof(char*));
            }
            ans[cnt++] = agg.entries[i].key;
        } else if (agg.entries[i].key) {
            free(agg.entries[i].key);
        }
    }
    free(agg.entries);

    qsort(ans, (size_t)cnt, sizeof(char*), cmp_str);
    *resultCount = cnt;
    return ans;
}
