    // 从第 M+1 项开始模拟生成
    int size = M;
    while (size < N) {
        int start = size - M;
        int mx = nums[start];
        int mn = nums[start];
        int has_dup = 0;

        // 更新最大值和最小值
        for (int i = start; i < size; i++) {
            int x = nums[i];
            if (x > mx) mx = x;
            if (x < mn) mn = x;
        }

        // 检查是否有重复值（M <= 10，双重循环即可）
        for (int i = start; i < size && !has_dup; i++) {
            for (int j = i + 1; j < size && !has_dup; j++) {
                if (nums[i] == nums[j]) {
                    has_dup = 1;
                }
            }
        }

        // 按题意生成当前项
        if (has_dup) {
            nums[size++] = mx + mn;
        } else {
            nums[size++] = mx - mn;
        }
    }

    return nums[N - 1];
}
