var countHikingPaths = function(grid, maxDiff) {
    var n = grid.length, m = grid[0].length;
    // 找出唯一最小、最大及其坐标
    var mn = grid[0][0], mx = grid[0][0];
    var si = 0, sj = 0, ei = 0, ej = 0;
    for (var i = 0; i < n; i++) {
        for (var j = 0; j < m; j++) {
            var v = grid[i][j];
            if (v < mn) { mn = v; si = i; sj = j; }
            if (v > mx) { mx = v; ei = i; ej = j; }
        }
    }

    // 记忆化数组，-1 表示未计算
    var memo = new Array(n);
    for (var i = 0; i < n; i++) {
        memo[i] = new Array(m);
        for (var j = 0; j < m; j++) memo[i][j] = -1;
    }

    function dfs(i, j) {
        if (i === ei && j === ej) return 1;
        if (memo[i][j] !== -1) return memo[i][j];
        var tot = 0;
        var h = grid[i][j];
        // 四方向：上、下、左、右
        if (i > 0) { var d = grid[i-1][j] - h; if (d > 0 && d <= maxDiff) tot += dfs(i-1, j); }
        if (i + 1 < n) { var d = grid[i+1][j] - h; if (d > 0 && d <= maxDiff) tot += dfs(i+1, j); }
        if (j > 0) { var d = grid[i][j-1] - h; if (d > 0 && d <= maxDiff) tot += dfs(i, j-1); }
        if (j + 1 < m) { var d = grid[i][j+1] - h; if (d > 0 && d <= maxDiff) tot += dfs(i, j+1); }
        memo[i][j] = tot;
        return tot;
    }

    return dfs(si, sj);
};
